window.__QUIZ_SUBJECT__=[{"id": "theory>Agricultural Science Practical>2000>1>a", "subject": "Agricultural Science Practical", "year": "2000", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "Identify specimens A, B and C", "images": [], "marking_scheme": "A - Nut and bolt;  B - Knapsack sprayer;  C - ldentification tag.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2000>1>b", "subject": "Agricultural Science Practical", "year": "2000", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "Give one function of each of Specimen A, B and C", "images": [], "marking_scheme": "A is used in tightening, fastening, fixing or holding joints together.    B is used for spraying or applying fungicides, insecticides.    -is used for spraying liquid fertilizers.  -is used for spraying herbicides.    C is used for identification of animals.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2000>1>c", "subject": "Agricultural Science Practical", "year": "2000", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "State two ways of maintaining each of specimen A and B", "images": [], "marking_scheme": "Ways of maintaining specimen A:  -Grease to avoid rusting.  -Straighten bent bolt or nut.    -Rethreading the worn-out threads.  -Store always in cool, dry place.    Ways of maintaining specimen B    -Wash and clean the tank, the filters and nozzles with water after use.  -Check the sprayer for leakage and any leakage should be blocked.  -Replace damage or worn-out parts, e.g., filters and nozzles.  -Remove the nozzles, clean and store seperately.  -Store the sprayer under cover.  -Free the nozzles of all blockages or clogs.  -Turn the container upside down after washing to drain properly.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2000>1>d", "subject": "Agricultural Science Practical", "year": "2000", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "Name three other farm implements that perform the same function as specimen B", "images": [], "marking_scheme": "-Motorized sprayer  -Boom sprayer  -Electrotyne sprayer  -Hand sprayer", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2000>1>e", "subject": "Agricultural Science Practical", "year": "2000", "type": "Practical", "sub_label": "e", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "Mention two precautions to be observed when using specimen B", "images": [], "marking_scheme": "-Wear protective clothing and a nose mask.  -Avoid eating. drinking or smoking.  -Wash/bath well after spraying.  -Do not blow a blocked nozzle with the mouth.  -Ensure that spraying is not against the wind.  -Avoid walking on freshly sprayed plots.  -Follow carefully instructions on the use of chemical to be sprayed", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2000>2>a", "subject": "Agricultural Science Practical", "year": "2000", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ECOLOGY : ROCK FORMATION", "question": "To what type of rock do each of specimens D, E, and F belong?", "images": [], "marking_scheme": "(i) D is an igneous rock   (ii) E is a sedimentary rock   (ii) F is an igneous rock", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2000>2>b", "subject": "Agricultural Science Practical", "year": "2000", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ECOLOGY : ROCK FORMATION", "question": "State the types of weathering caused by each of specimens G, H, and l", "images": [], "marking_scheme": "Specimen G (Earthworm) - Physical/mechanical  Specimen H (Water) - Physical and Chemical  Specimen I (Ice Block) - Physical / mechanical", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2000>2>c", "subject": "Agricultural Science Practical", "year": "2000", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ECOLOGY : ROCK FORMATION", "question": "Give two ways by which weathering causes each of specimens G, H, and I.", "images": [], "marking_scheme": "Specimen G burrows into rocks and creates wide cleavages which cause rocks to disintergrate into smaller particles and this creates room for water and air which aid rock disintegration.  Specimen H dissolves to form weak acids that dissolve rock particles and attaches H and OH ions to some compounds to form minerals. Running water drags rock particles along and these collide with themselves and wall and thus breakdown. The force of running water pulls away rock particles from embankments/floor of channels.  Specimen I - conversion of water into ice results in increase in Volume and pressure exerted within the rock causes it to crack and fall apart. Also movement of ice along a path leads to further dislodgement of particles.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2000>2>d", "subject": "Agricultural Science Practical", "year": "2000", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT", "question": "State three ways in which specimen D is important to agriculture", "images": [], "marking_scheme": "-It forms soil when weathered.  -It serves as a source of soil nutrients/elements.  -It can be pilled up and used to check erosion.  -It can be used to construct farm structures.  -It can also be used to construct access roads.  -It can also damage tools when in use.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2000>3>a", "subject": "Agricultural Science Practical", "year": "2000", "type": "Practical", "sub_label": "a", "group": "", "topic": "CROP PROTECTION : DISEASES OF CROPS", "question": "State each of the disease condition observed on specimens J (MAIZE PLANT) and K (CASSAVA LEAF) and their causative agents.", "images": [], "marking_scheme": "Specimen J is maize plant with leaves showing a mosaic pattern/infection, tomato plant, showing leaf curl.    The causative agent for this Condition is virus.    Specimen K is cassava leaf, showing leaf spot.    The causative agent is fungus.", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2000>3>b", "subject": "Agricultural Science Practical", "year": "2000", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PROTECTION : DISEASES OF CROPS", "question": "Explain the mode of transmission of the diseases on each of specimens J and K.", "images": [], "marking_scheme": "For specimen J, the virus is transmitted by an aphid vector.  For specimen K, the fungus is air- borne, water and rain splash", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2000>3>c", "subject": "Agricultural Science Practical", "year": "2000", "type": "Practical", "sub_label": "c", "group": "", "topic": "CROP PROTECTION : DISEASES OF CROPS", "question": "State two effects each of the diseases on Specimens J and K and two control measures of each", "images": [], "marking_scheme": "Specimen J (effects):  -It results in stunted growth of plants.  -It leads to reduction in yield of plants.  -It causes reduction in the photosynthetic area of the leaf.  Control measures include:  -early planting:  -removal and burning of infected plants;  -eradication of insect vectors;  -use of resistant varieties; and   -crop rotation    For specimen K (effects);  -It causes reduction in yield of crop or plant.  -It leads to the reduction in the rate of growth of plants.  -It also leads to reduction in the photosynthetic area of the leaves.    Control measures include:  -application of fungicides,  -use of resistant varieties,  -removal and burning of infected plants, and  -crop rotation.", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2000>3>d", "subject": "Agricultural Science Practical", "year": "2000", "type": "Practical", "sub_label": "d", "group": "", "topic": "CROP PROTECTION : DISEASES OF CROPS", "question": "Name two other diseases of specimen K.", "images": [], "marking_scheme": "Other diseases of specimen K are;  -Cassava mosaic  -Cassava blight", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2000>4>a", "subject": "Agricultural Science Practical", "year": "2000", "type": "Practical", "sub_label": "a", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "ldentify specimens L, M and N", "images": [], "marking_scheme": "Specimen L is NPK Fertilizer  Specimen M is Tilapia Fish  Specimen N is Litmus Paper", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2000>4>b", "subject": "Agricultural Science Practical", "year": "2000", "type": "Practical", "sub_label": "b", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "ldentify specimens O and P, using specimen N", "images": [], "marking_scheme": "Litmus paper test shows that specimen O is acidic while P is neutral    Acidic liquid (Fluid)  Neutral liquid (Distilled water)", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2000>4>c", "subject": "Agricultural Science Practical", "year": "2000", "type": "Practical", "sub_label": "c", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "In which of specimens O and P will specimen M survive better?", "images": [], "marking_scheme": "Specimen M will survive better in P", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2000>4>d", "subject": "Agricultural Science Practical", "year": "2000", "type": "Practical", "sub_label": "d", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "What is the relevance of specimen L in the production of specimen M?", "images": [], "marking_scheme": "Specimen L is used to fertilize a fish pond in small quantities to provide nutrients for the growth of phytoplanktons which are eaten by fish", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2000>4>e", "subject": "Agricultural Science Practical", "year": "2000", "type": "Practical", "sub_label": "e", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "State two pond management practices to improve specimen O for the production of specimen M.", "images": [], "marking_scheme": "Pond management practises to improve specimen O for the production of specimen M includes:    desilting.  liming  fertilizer application", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2000>4>f", "subject": "Agricultural Science Practical", "year": "2000", "type": "Practical", "sub_label": "f", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "List three ways by which the loss of specimen M can be controlled in a farm.", "images": [], "marking_scheme": "Ways by which the loss of specimen M can be controlled in a farm are;    -Control gate to prevent excess out of flow of water from dam  -Errection of spill-way.  -Maintaining patrol to prevent stealing.  -Control of predators.,  -Control of diseases.  -Avoid over flooding by erecting barriers across flood part", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2000>4>g>i", "subject": "Agricultural Science Practical", "year": "2000", "type": "Practical", "sub_label": "i", "group": "", "topic": "ANIMAL PRODUCTION : AQUACULTURE", "question": "State one method each of partial harvesting of specimen M.", "images": [], "marking_scheme": "Partial harvesting of specimen O can be achieved through the use of ;    -Hook and line  -Traps,  -Baskets,  -Net and spears", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2000>4>g>ii", "subject": "Agricultural Science Practical", "year": "2000", "type": "Practical", "sub_label": "ii", "group": "", "topic": "ANIMAL PRODUCTION : AQUACULTURE", "question": "State one method each of complete harvesting of specimen M.", "images": [], "marking_scheme": "Method of complete harvesting of specimen O is by drainage of the pond,", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2001>1>a", "subject": "Agricultural Science Practical", "year": "2001", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "In what three ways can specimen A (RADIO TRANSMITTER) enhance farmers' productivity?", "images": [], "marking_scheme": "Specimen A (Radio Transmitter) will enhance farmers' productivity in the following ways:    -Farmers learn of modern practices through it.  -Farmers are informed of the weather forecasts.  -Available inputs and policies of government are communicated through the medium.  -Market information is relayed for farmers' benefit, e.g. for better marketing of the product.  -Notices of meetings/community gatherings are communicated through the medium", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2001>1>b>i", "subject": "Agricultural Science Practical", "year": "2001", "type": "Practical", "sub_label": "i", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "Name the operation for which specimen B (BURDIZZO PLIER) is used.", "images": [], "marking_scheme": "Specimen B is burdizzo plier and it is used for castration, that is, cutting the spermatic Cord of the male.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2001>1>b>ii", "subject": "Agricultural Science Practical", "year": "2001", "type": "Practical", "sub_label": "ii", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "Describe how specimen B is used", "images": [], "marking_scheme": "Specimen B ( burdizzo pliers) can be used in the following ways:    -The burdizzo plier has to be opened and the spermatic cord located and inserted between the pliers.  -The burdizzo plier is then clamped down on the spermatic cord for a minute, one after the other. Then release and remove the pliers.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2001>1>b>iii", "subject": "Agricultural Science Practical", "year": "2001", "type": "Practical", "sub_label": "iii", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "State two maintenance practices for specimen B", "images": [], "marking_scheme": "Methods of maintenance:    -clean after use or wash and dry,  -grease or oil metal parts,  -store in a rack in a cool, dry place,  -protect from termite attack if it is a wooden handle", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2001>1>c", "subject": "Agricultural Science Practical", "year": "2001", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "Give three uses of specimen C (BASKET)", "images": [], "marking_scheme": "Uses of specimen C (Basket):    It is used for the transport of farm produce and storage of produce. I  It can also be used as a sieve as well as to crop fishes.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2001>1>d", "subject": "Agricultural Science Practical", "year": "2001", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "State the importance of specimen D (EGG CANDLER)", "images": [], "marking_scheme": "Importance of specimen D -Egg Candler:    It is used for candling eggs to detect its fertility or viability.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2001>2>a", "subject": "Agricultural Science Practical", "year": "2001", "type": "Practical", "sub_label": "a", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "Classify specimens E (GRASSHOPPER), F (COTTON STAINER), and G (WEEVIL)according to the type of mouthparts they possess.", "images": [], "marking_scheme": "Classification of specimens based on the type of mouthparts they possess are:    Specimen E: Grasshopper - mouth part is used for biting and chewing.  Specimen F: Cotton stainer -mouth part is used for piercing and sucking  Specimen G: Weevil - the mouth part is used for biting and boring or boring alone.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2001>2>b", "subject": "Agricultural Science Practical", "year": "2001", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "State two damages done to crops by each of specimens E, F, G, and H (TERMITES)", "images": [], "marking_scheme": "Damages done to crops by:    Specimen E (Grasshopper);  -It destroys the leaves (defoliation)  -It destroys succulent parts of the shoot system.  -lt reduces the photosynthetic capacity of crops.  -It reduces yields of crops.    Specimen F (Cotton stainer);  -It sucks sap from cotton bolls.  -It destroys the bolls of a cotton fruit.  -It stains the lint.  -İt attacks and destroys okro.  -It can transmit diseases.  -It creates vents for secondary infection.  -It reduces yields.    Specimen G (Weevil);  -It reduces seed quality.  -It reduces seed viability by destroying the embryo.  -It creates vents for secondary infection.  -It reduces weight of stored grains.    Specimen H (Termites);  -It causes lodging of crops.  -It damages underground storage organs of crops.  -It destroys seedlings.  -It destroys produce being dried on the field.  destroys timber.  -It reduces yields.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2001>2>c", "subject": "Agricultural Science Practical", "year": "2001", "type": "Practical", "sub_label": "c", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "State two control measures of each of specimens G and H.", "images": [], "marking_scheme": "Control measures for Specimen G (Weevil) are:  -proper drying of grains before storage  -timely and prompt harvesting of a crop   -use of insecticides  -fumigation of storage facilities -storage of grains in airtight containers  -smoking of grains    Control measures for Specimen H Termites;  -smoke the termitarium  -chemical control  -regular cultivation  -physically digging out the queen  -destroy the termitarium", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2001>3>a", "subject": "Agricultural Science Practical", "year": "2001", "type": "Practical", "sub_label": "a", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "State one method of propagating each of specimens I (CASSAVA), J (YAMSEED), K (COCOYAM), and L (GINGER)", "images": [], "marking_scheme": "Specimen l (Cassava) - stem cutting  Specimen J (Yamseed) - yam or yam sets /  mini sets  Specimen k (Cocoyam) tuber, stem/vine cuttings  Specimen L (Ginger) - rhizomes", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2001>3>b", "subject": "Agricultural Science Practical", "year": "2001", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "State three advantages of staking specimen J.", "images": [], "marking_scheme": "The advantages of staking specimen J (yam) are;  -It increases yield.  -It improves air circulation within the farm.  -The leaves are better exposed for photosynthesis   -It reduces the attack of pests and  -it minimizes damage to vines.  -It increases farmers' ease of movement.  -It reduces rain splash which can reduce photosynthetic area", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2001>3>c", "subject": "Agricultural Science Practical", "year": "2001", "type": "Practical", "sub_label": "c", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS~~CROP PROTECTION : DISEASES OF CROPS", "question": "Give two pests and two diseases of specimen I", "images": [], "marking_scheme": "Pests of specimen I(Cassava) are;  -aphids,  -green spider mite,  -rodents,  -grasshoppers/locusts.    Disease of specimen I(Cassava) are  -mosaic,  -leaf spot,  -white thread.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2001>3>d", "subject": "Agricultural Science Practical", "year": "2001", "type": "Practical", "sub_label": "d", "group": "", "topic": "BASIC CONCEPTS : PROBLEMS OF AGRICULTURAL DEVELOPMENT AND POSSIBLE SOLUTIONS", "question": "Name the toxic Substance present in specimen I and give one process of reducing it.", "images": [], "marking_scheme": "Toxic substance present in Specimen I(Cassava) and the toxic substance is HCN (hydrocynanide acid) The substance can be reduced through;    Roasting / frying  Drying  Fermenting,  Boiling  Soaking.  Grating and  Squeezing out the water,", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2001>3>e", "subject": "Agricultural Science Practical", "year": "2001", "type": "Practical", "sub_label": "e", "group": "", "topic": "BASIC CONCEPTS : MEANING AND IMPORTANCE OF AGRICULTURE", "question": "Give two uses of specimen L.", "images": [], "marking_scheme": "Uses of specimen L (Ginger):     Is used for spicing of food / seasoning  for drink making / beverage  For medicinal purposes", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2001>4>a", "subject": "Agricultural Science Practical", "year": "2001", "type": "Practical", "sub_label": "a", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT", "question": "State four effects of specimen M (LIVER FLUKE) on farm animals", "images": [], "marking_scheme": "Effects of specimen M(Liver Fluke) on farm animals are:  -It destroys the liver tissues.  -It causes general weakness of the animal  -It causes the obstruction of the bile duct  -It inhibits the production of bile from the liver  -It prevents the flow of bile from the gall bladder into the small intestine  -Lipid digestion is impaired  -Animal emaciates  -It leads to loss of yields in terms of milk and meat  -It leads to death in extreme cases.  -Excessive loss of blood from the liver may cause anaemia.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2001>4>b", "subject": "Agricultural Science Practical", "year": "2001", "type": "Practical", "sub_label": "b", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL IMPROVEMENT", "question": "Name the primary and intermediate host of specimen M", "images": [], "marking_scheme": "The primary host of specimen M is ruminants while the intermediate host is water snail", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2001>4>c", "subject": "Agricultural Science Practical", "year": "2001", "type": "Practical", "sub_label": "c", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL IMPROVEMENT", "question": "State three adaptive features of specimen N (TAPEWORM) which enable it to survive in its host", "images": [], "marking_scheme": "Adaptive features of specimen N (Tapeworm) which enable it to survive in the host are:  -It has very high absorptive surface area,  -Specimen possesses four suckers with which it attaches itself to the walls of the small intestine.  -It possesses two rows of hooks which enable it to have a firm grip of the small intestine.  -The whole body is covered with a cuticle which prevents it from being digested by the digestive enzymes of the host.  -It has the ability to absorb digested food materials from the small intestine with the whole body.  -It is highly prolific, i.e; it has a fast rate of reproduction", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2001>4>d", "subject": "Agricultural Science Practical", "year": "2001", "type": "Practical", "sub_label": "d", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT", "question": "State three control measures of each of specimens M and N in livestock management", "images": [], "marking_scheme": "The control measures for specimen M (Liver fluke) are:  -control snails on pasture using copper sulphate solution  -regular deworming of animals  -rotational grazing  -avoid grazing near streams  -burning of infected pastures    Control measures for specimen N (Tapeworm) are:  -proper sewage disposal or farm hygiene  -proper cooking of meat before consumption  -inspection of animal before slaughter  -deworming of animals  rotational grazing  -burning of infected pastures  -proper meat inspection before selling", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2002>1>a", "subject": "Agricultural Science Practical", "year": "2002", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "Study carefully the experimental set-up labelled A and use it to answer questions (a) - (d)    State the aim of the experimental set-up.", "images": [], "marking_scheme": "The aim of the experimental setup is to determine the different soil particles or fractions or the soil texture.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2002>1>b", "subject": "Agricultural Science Practical", "year": "2002", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "Describe briefly the procedure for carrying out the experiment.", "images": [], "marking_scheme": "The procedure for carrying out the experiment is first, some quantity of soil is put in a measuring cylinder and sufficient water is added. A small quantity of hydrogen peroxide or sodium bicarbonate is also added. The container is then stirred and shaken vigorously and the solution is allowed to settle for at least five hours.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2002>1>c", "subject": "Agricultural Science Practical", "year": "2002", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "Describe briefly your observation on the experimental set-up.", "images": [], "marking_scheme": "The observations are:    -Soil particles settled down in layers, according to the weights and sizes of particles.  -Gravel settled first, followed by coarse sand, fine sand, silt, and clay which settled last while the organic matter floated on top.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2002>1>d", "subject": "Agricultural Science Practical", "year": "2002", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "Outline how the different soil particle sizes can be estimated.", "images": [], "marking_scheme": "The different soil particle sizes can be estimated by:    Obtaining the total height of the sediments directly from the measuring cylinder (T)  Reading the height of sand, e.g. HSA  Reading the height of silt, e.g. HSI  Reading the height of clay, e.g. HCL  Calculating sand proportion, i.e; HSA/T x 100  Calculating proportion of silt i.e HSI/T x 100  Calculating the proportion of clay, i.e; HSL/T x 100", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2002>2>a", "subject": "Agricultural Science Practical", "year": "2002", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE", "question": "ldentify specimens B, C, and D", "images": [], "marking_scheme": "Specimen B is NPK or compound fertilizer; Specimen C is wood ash and Specimen D is animal dung.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2002>2>b", "subject": "Agricultural Science Practical", "year": "2002", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE", "question": "Give two observable physical properties of each.", "images": [], "marking_scheme": "The observable physical properties of the specimens are:    Specimen B = NPK Higroscopic;    The specimen is hard to touch, i.e; it is solid and strong.  It is granular in nature and  It is grey in colour and odourless.    Specimen C wood ash;     It is grey in colour.  It is smooth and velvety to touch  It is powdery in form  It is dry and odourless.    Specimen D animal dung    It is dark brown or black in colour  lt has a bad odour.   it is bulky in nature.  It is always sticky and soft in a fresh form.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2002>2>c", "subject": "Agricultural Science Practical", "year": "2002", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE", "question": "State two main nutrients supplied by each of specimens B and D.", "images": [], "marking_scheme": "The major nutrients supplied by the specimen are:    Specimen B = N, - P, -K,  Specimen D = N, -P, -K.", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2002>2>d", "subject": "Agricultural Science Practical", "year": "2002", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE", "question": "State two methods of application of specimen C on the field.", "images": [], "marking_scheme": "The methods of applying specimen C on the field are:    It can be spread on the farm before ploughing.  It can be put in holes, before planting  It can be placed at the base of plant stem  It can be allowed to be in rows before ridging", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2002>3>a", "subject": "Agricultural Science Practical", "year": "2002", "type": "Practical", "sub_label": "a", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "ldentify specimen E.", "images": [], "marking_scheme": "Specimen E is a caterpillar or stem borer.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2002>3>b", "subject": "Agricultural Science Practical", "year": "2002", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "State four damages caused to crops by the specimen", "images": [], "marking_scheme": "The damage caused to crops by the specimen are:    lts larva chews off green leaves of plants thereby causing defoliation  It destroys flowers, fruits as well as buds.  It creates vents that serve as avenues for secondary infection  It leads to a reduction in the quality of leaves.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2002>3>c", "subject": "Agricultural Science Practical", "year": "2002", "type": "Practical", "sub_label": "c", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "Briefly describe its life cycle", "images": [], "marking_scheme": "The life cycle of the specimen can be represented as; Egg → Larva → Pupa → Adult. Its eggs are laid on the leaves and they hatch into destructive larva stage. After 10 days, the larva develops into docile pupa and After 2 weeks, the pupae develop into adults", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2002>3>d>i", "subject": "Agricultural Science Practical", "year": "2002", "type": "Practical", "sub_label": "i", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "Name the stage of development at which the specimen is most dangerous to crops.", "images": [], "marking_scheme": "The stage of development at which the specimen is most dangerous is the larval stage:", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2002>3>d>ii", "subject": "Agricultural Science Practical", "year": "2002", "type": "Practical", "sub_label": "ii", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "Give one reason for your answer", "images": [], "marking_scheme": "The reasons for my answer is that the larva has biting and chewing mouthparts which enable it to feed voraciously and destroy the vegetative parts of the plant within a short time.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2002>3>e", "subject": "Agricultural Science Practical", "year": "2002", "type": "Practical", "sub_label": "e", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "List three control measures of the specimen.", "images": [], "marking_scheme": "The measures that can be taken to control the specimen are:    spraying with insecticides.  mechanical control e.g. hand-picking.  biological control e.g. by birds, beetles  timely planting of crops. brewers dried grains.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2002>4>a", "subject": "Agricultural Science Practical", "year": "2002", "type": "Practical", "sub_label": "a", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL NUTRITION", "question": "Which of specimens F, G, and H is the most common source of energy in livestock rations?", "images": [], "marking_scheme": "The common source of energy in livestock rations among the specimens is ground sorghum.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2002>4>b", "subject": "Agricultural Science Practical", "year": "2002", "type": "Practical", "sub_label": "b", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL NUTRITION", "question": "Mention one ingredient in specimen I which has a laxative effect on farm animals", "images": [], "marking_scheme": "The ingredients in specimen I that have a laxative effect on farm animals are;    rice bran,  maize bran or offal,  wheat bran or offal  brewers dried grains", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2002>4>c", "subject": "Agricultural Science Practical", "year": "2002", "type": "Practical", "sub_label": "c", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL NUTRITION", "question": "State three important feed ingredients in specimen I essential for bone and teeth formation in livestock.", "images": [], "marking_scheme": "The important feed ingredients in Specimen I essential for bone and teeth formation are;    Oyster shell,  bone meal,  fish meal,  dicalcium phosphate (DCP) and  periwinkle shell.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2002>4>d", "subject": "Agricultural Science Practical", "year": "2002", "type": "Practical", "sub_label": "d", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "Name four types of specimen l and the class of poultry to which each type is fed", "images": [], "marking_scheme": "The types of specimen l and the class of poultry to which each type is fed is presented in the table below;  Types of FeedPoultry ClassChicks mashChicks Breeders mashBreedersLayers mashLayersGrower mashGrowersBroiler starterBroiler chicksBroiler finisherBroiler", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2002>4>e", "subject": "Agricultural Science Practical", "year": "2002", "type": "Practical", "sub_label": "e", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "Name four farm animals that feed largely on specimen J.", "images": [], "marking_scheme": "The animals that feed on specimen J are;   rabbits  goat,  cattle and  sheep", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2002>4>f", "subject": "Agricultural Science Practical", "year": "2002", "type": "Practical", "sub_label": "f", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL NUTRITION", "question": "State four plant protein sources used in livestock feeds.", "images": [], "marking_scheme": "The plant protein sources used in livestock feeds are;    Palm kernel cake,  Soya bean meal,  Cotton seed cake  Sesame seed cake,  Groundnut cake meal,  Sunflower seed cake and  Brewers dried grain", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2003>1>a>i", "subject": "Agricultural Science Practical", "year": "2003", "type": "Practical", "sub_label": "i", "group": "", "topic": "AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "Describe the physical properties of each of Specimens B (SAND), C (CLAY), and D (LOAM)", "images": [], "marking_scheme": "Physical properties (before wetting) of Specimen B Sand:    It consists of coarse and fine particles.  It is light grey as well as light brown in colour.  The grains are separate and do not stick together, they are loosely or Closely packed.  It has good pore spaces and are well aerated,    Specimen C is Clay and the physical properties are as follows:    It consists of very small and fine particles closely packed together  Its colours may be light brown or yellowish-brown as well as straw-coloured.  Most clay can be powdery, smooth or velvety.    Specimen D is Loam:    It contains the presence of humus and organic matter.  The colours are dark brown, black and greyish black.  Loamy soil is always friable and consistent.  Its particles are loosely packed.  It has moderate pore spaces.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2003>1>a>ii", "subject": "Agricultural Science Practical", "year": "2003", "type": "Practical", "sub_label": "ii", "group": "", "topic": "AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "To about 10ml each of the specimens B, C and D, add about 5ml of specimen O and using the hand, mix well. Describe the physical properties of each specimen?", "images": [], "marking_scheme": "Physical properties after wetting of Specimen B is Sand:    Most sandy soil are always gritty after wetting  It cannot be moulded and is not plastic  It is easily permeable to water and very porous.    Specimen C is Clay;    Clay soil are sticky after wetting  It can easily be moulded into plastic.  It is not permeable to water and has low porosity.    Specimen D is Loam;    Loamy soil is partially sticky after wetting.  Loamy soil moulds but breaks when an attempt to form a ring is made.  Loamy soil is moderately porous after wetting.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2003>1>b", "subject": "Agricultural Science Practical", "year": "2003", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "Which of the specimens B, C, and D should be considered of greater value to farmers? Give two reasons for your answers", "images": [], "marking_scheme": "Specimen D is Loamy soil is of greatest value to farmers: Reason:    It has a moderate water retention capacity.  It also has a higher proportion of organic matter.  Most loamy soil is adequately aerated.  They are also moderately porous.  It has high capillarity.  it is rich in plant nutrients  Loamy soil is rich in soil microbes.", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2003>1>c", "subject": "Agricultural Science Practical", "year": "2003", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "State three ways of improving each of the other two specimens not mentioned in 1(b) above", "images": [], "marking_scheme": "Ways of improving specimen B Sand:    Áddition of organic matter to sandy soil can improve its content.   Application of lime to sandy soil can restore its content.  Constant application of irrigation can improve sandy soil.  Application of clay to sandy sol can improve its contents.  The practice of fallow can improve sandy soil.  Sandy soil can be improved by planting cover crops in the farm.  Application of inorganic fertilizers can also improve sandy soil.  Mulching restores the soil's fertility and ensures a good yield.  Ways of Improving Specimen C:    Clay soil can be improved by the addition of organic matter.  It can further be improved by the application of lime  Drainage of excess water from the soil can improve clay soil.  An introduction of sandy soil can improve clay soil  Practising fallow farming for sometime can improve the clay soil.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2003>2", "subject": "Agricultural Science Practical", "year": "2003", "type": "Practical", "sub_label": "2", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "State three functions and two methods of maintaining each of specimens F (HOE), H (RAKE), and K (PLIERS).", "images": [], "marking_scheme": "Specimen F is Hoe. Its functions are as follows:    It can be used for weeding.  It can also be used for planting and transplanting  It can be used for making heaps of ridges.  It can be used for harvesting crops as well as digging of drainage channels.  Hoe is a good implement for land clearing.  Maintenance of Specimen F and H:    Hoe can be maintained by sharpening blunt edges.  By washing blade after use.  By application of grease before long time storage.  By washing blade and dry after use,  It can also be kept in a cool dry place after use.  Specimen H (Rake). Functions of Rake include:    Cleaning and packing plant debris,  It can be used for breaking up soil clods.  It can be used for levelling the soil.  It can be used for spreading manure.  Rake is useful in spreading grains, and farm produce etc.  Maintenance of Rake;    Rake can be maintained by straightening bent prongs.  By applying oil to prevent termite attack  Application of grease before long time storage.  By washing and drying the tool after use for spreading soil or fertilizers.  By quick replacement of damaged prongs or handles.  Specimen K is called (Pliers) Functions:    for holding or handling bots and nuts or for tightening  It can be used to cut wires  For gripping firmly and twisting wires.  Also good Tor removal of nails.  It can be used for bending strong wires or metal pieces.  Maintenance of Specimen K;    Piers can be maintained by oil or greasing after use.  Proper lubrication should be done in case of long time use.  Store the plier in a dry place", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2003>3>a", "subject": "Agricultural Science Practical", "year": "2003", "type": "Practical", "sub_label": "a", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "Identify specimens L, N, and Q", "images": [], "marking_scheme": "ldentification of Specimens;    L - urea,  N - lime / quicklime / slaked lime,  Q - wood ash.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2003>3>b", "subject": "Agricultural Science Practical", "year": "2003", "type": "Practical", "sub_label": "b", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "State three agricultural uses of each specimen N and Q", "images": [], "marking_scheme": "Agricultural uses of specimen N (Lime):    Lime is used in the soil to correct soil acidity.  It helps to supply calcium for root development.  It can be used to lime fish ponds to correct water acidity.  It can be used in improving clay soil structure.  It brings about flocculation of fine clay particles in fish ponds as well as reducing turbidity of ponds.  It improves the growth of soil microbes and also renders more available the nutrients locked in clay soils.    Agricultural uses of specimen Q (Wood ash)    is used for correcting soil acidity.  It is also a good natural pesticide for controlling insect pests of seedlings and vegetables;  it provides potassium for plant growth and a good component of compost; lime increases grown of phytoplankton in fish ponds and can be used to correct acidity in fish ponds.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2003>3>c", "subject": "Agricultural Science Practical", "year": "2003", "type": "Practical", "sub_label": "c", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "List two crops each which require each of the specimens L, N and Q in large quantities for good yields", "images": [], "marking_scheme": "Crops that requires Specimen L (Urea) are as follows:    Maize;  Millet;  Rice;  Guinea corn;  Wheat:  Leafy vegetables.    Crops that requires Specimen N    groundnut:  pigeon peas;  cowpea,  soyabeans;  bambará groundnut.    Crops that requires Specimen Q (Wood ash) are as follows:    cassava,  cocoyams  sweet potato;  Irish potato;  yams;  carrots.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2003>3>d", "subject": "Agricultural Science Practical", "year": "2003", "type": "Practical", "sub_label": "d", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "State three methods of applying specimen L on a farm", "images": [], "marking_scheme": "Methods of applying specimen L(Urea) to the soil are as follows:-    Urea can be applied through ploughing into the soil using a plough, and it can be done through drilling into the soil using a plough.  Ring method and covering can be used as a way of applying urea to the soil;  Also, side dressing and covering methods can also be used.;  Broadcast method can equally be applied.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2003>4>a", "subject": "Agricultural Science Practical", "year": "2003", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE", "question": "State the main nutrient obtainable from each of the Specimen G (BONE), and P ( DRIED ANIMAL BLOOD) and two main nutrients obtainable from Specimen T (FISH)", "images": [], "marking_scheme": "Main nutrients from specimen    G(bone) is Mineral;  P (dried animal blood)- protein.  T (fish)-protein, oil.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2003>4>b", "subject": "Agricultural Science Practical", "year": "2003", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE", "question": "State three functions for each of the two main nutrients obtainable from specimen T", "images": [], "marking_scheme": "Functions of the major nutrients obtainable from specimen T    (i) Protein. -    Protein assists in the growth and bodybuilding,  It assists in repairs of damaged tissues as well as replacement of worn out body tissues;  it synthesizes the enzymes and hormones as well as other body fluids  Proteins help in the formation of animal products such as milk, eggs, wool, skin, fur and leathers.  (ii) Fats and oils; -    Fats and oil is used for insulation.  They also acts as carriers of fat-soluble Vitamins,  Fats provide protective coverage to organs like intestines and kidneys  It's a good source of energy and can be very medicinal", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2003>4>c", "subject": "Agricultural Science Practical", "year": "2003", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE", "question": "Name one feed ingredient that can be prepared from each of specimens G, P, and T.", "images": [], "marking_scheme": "Obtainable feed ingredients from Specimen;    Bone meal can be obtained from Specimen G;  Blood meal can be obtained from Špecimen P:  Fish meal can be obtained from Specimen T.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2003>4>d", "subject": "Agricultural Science Practical", "year": "2003", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE", "question": "Give two disadvantages of using the ingredient prepared from specimen P in compounding livestock feed.", "images": [], "marking_scheme": "Disadvantages of using the ingredient from specimen P (blood meal) in compounding livestock feed:    The use of blood meal may be a source of disease infection.  The blood meal cause a lot of flies,  It also has a low palatability.  Blood meal can easily be contaminated if not well protected.  It has poor storage ability.  It is also known for its repugnant odour.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2004>1>a", "subject": "Agricultural Science Practical", "year": "2004", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ECOLOGY : DRAINAGE", "question": "Observe the experimental set-ups A and B in which 120ml of water was made to drain through each of the different soils contained in the funnels.    Use the experimental set-ups to answer Questions (a) - (d).    State the volume of water collected in each of the measuring cylinders in setups A and B.", "images": [], "marking_scheme": "Volume of water collected in set-up A= x ml, Volume of water collected in Set-Up B = yml", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2004>1>b", "subject": "Agricultural Science Practical", "year": "2004", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ECOLOGY : DRAINAGE", "question": "Calculate the volume of water retained in each of the set-ups A and B.", "images": [], "marking_scheme": "Volume of water retained in A = 120ml - xml = pml        Volume of water retained in B = 120ml - yml = qml", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2004>1>c>i", "subject": "Agricultural Science Practical", "year": "2004", "type": "Practical", "sub_label": "i", "group": "", "topic": "AGRICULTURAL ECOLOGY : DRAINAGE", "question": "Calculate the percentage of:  water which percolated through each of the soils in set-ups A and B", "images": [], "marking_scheme": "Percentage of water which percolated through A  =xml/120 x 100/1 =R%  Percentage of water which percolated through B  =yml/120 x 100/1 =S%", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2004>1>c>ii", "subject": "Agricultural Science Practical", "year": "2004", "type": "Practical", "sub_label": "ii", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT", "question": "Calculate the percentage of:  water retained in each of the soils in set-ups A and B.", "images": [], "marking_scheme": "Percentage of water retained in A  =pml/120ml x  100/1= U%  Percentage of water retained in B  =qml/120ml x  100/1= V%", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2004>1>d", "subject": "Agricultural Science Practical", "year": "2004", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ECOLOGY : ENVIRONMENTAL FACTORS AFFECTING CROP AND ANIMAL DISTRIBUTION AND PRODUCTION", "question": "Which one of the soils in set-ups A and B will be better for crop production? Give three reasons for your answer.", "images": [], "marking_scheme": "Soil in set-up A will be better for crop production.     Reasons;    Contains O.M. not present or sparse in B  The O.M. binds soil particles and improves soil structure in A  Moderate air space/porosity  O.M. is a source of nutrients for plant growth  The rate of leaching of nutrients in Ais lower in A than B  Soil in set-up A has a greater capacity for regulating soil acidity  Regulates soil temperature better  Likely to contain more microbes involved in mineralization  Retains water better than B.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2004>2>a", "subject": "Agricultural Science Practical", "year": "2004", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "Name specimens C, D, F, G and M", "images": [], "marking_scheme": "Naming of specimens;    C - ranging pole,  D - thread/line,  F- nut,  G - fish hook,  M -grass stem/elephant grass stem.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2004>2>b", "subject": "Agricultural Science Practical", "year": "2004", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "Name the fishing equipment that can be improvised by assembling specimens C,D,F,G and M.", "images": [], "marking_scheme": "Name of farm equipment that can be assembled from specimens - hook and line/fishing line", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2004>2>c", "subject": "Agricultural Science Practical", "year": "2004", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "State four advantages of using the equipment named in (b) above.", "images": [], "marking_scheme": "Advantages of using the equipment:    easy to assemble  use does not require much expertise  cheap to acquire  can be used in all water bodies  all components are easily available  little cost of maintenance.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2004>2>d", "subject": "Agricultural Science Practical", "year": "2004", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "Explain how the equipment named in (b) is used.", "images": [], "marking_scheme": "How the equipment is used:    fix the tread to ranging pole, grass stem, nut, and the hook  fix a suitable bait to the hook  determine fishing depth and adjust the position of float  insert into water: sinker drags the hook plus bait down the water depth  watch float for an indication of a catch/sinking of float  if a fish has been caught, pull it out of water  remove fish from hook.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2004>2>e", "subject": "Agricultural Science Practical", "year": "2004", "type": "Practical", "sub_label": "e", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "List five other pieces of equipment that can perform a similar function as the one named in (b).", "images": [], "marking_scheme": "Other equipment that can perform similar function as the equipment:    fish trap  Seine net  drag net/trawl  cast net  spears  fish baskets/basket", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2004>3>a", "subject": "Agricultural Science Practical", "year": "2004", "type": "Practical", "sub_label": "a", "group": "", "topic": "CROP PROTECTION : WEEDS", "question": "Give the botanical name of each of specimens I (Common wireweed) J (coatbuttons), K (Giant star grass), and L (cogongrass)", "images": [], "marking_scheme": "Botanical name of specimens:-    I  = Šida acuta,  J = Tridax procumbens,  K = Cynodon plectostachyum/nlemfluensis/ (specie),  L = Imperata cylindrical.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2004>3>b", "subject": "Agricultural Science Practical", "year": "2004", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PROTECTION : WEEDS", "question": "Describe Specimen K", "images": [], "marking_scheme": "Description of specimen K:    short and hardly visíble inter-nodes  weak stem  leaf sheath covers much of the internodes  roots are present at nodes  leaves shoot from nodes  leaves are long and narrow  leaves have parallel venation  has adventitious/fibrous roots  is a creeping, stoloniferous grass.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2004>3>c", "subject": "Agricultural Science Practical", "year": "2004", "type": "Practical", "sub_label": "c", "group": "", "topic": "CROP PROTECTION : WEEDS", "question": "Describe the process of preparing silage from specimen K", "images": [], "marking_scheme": "Process of preparing silage from specimen K:    harvest plant before flowering  chop plant into pieces  partially wilt chopped material under the sun  put wilted material into silage pit  compress material well  sprinkle a little dilute mineral acid  add nitrogen fertilizer e.g. urea  repeat the preceding steps until pit is full  cover pit to make it air and watertight for a least two/three weeks", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2004>3>d", "subject": "Agricultural Science Practical", "year": "2004", "type": "Practical", "sub_label": "d", "group": "", "topic": "CROP PROTECTION : WEEDS", "question": "Mention two methods for the effective control of specimen L on a farm.", "images": [], "marking_scheme": "Control of specimen L on the farm:    deep ploughing to expose rhizomes  destruction of exposed rhizomes.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2004>4>a", "subject": "Agricultural Science Practical", "year": "2004", "type": "Practical", "sub_label": "a", "group": "", "topic": "PARASITES", "question": "ldentify specimens N, O and Q.", "images": [], "marking_scheme": "ldentification of specimens:    N - Ascaris,  O - Tick,  Q - Tapeworm", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2004>4>b", "subject": "Agricultural Science Practical", "year": "2004", "type": "Practical", "sub_label": "b", "group": "", "topic": "PARASITES", "question": "Name one host of each of specimens N, O and Q.", "images": [], "marking_scheme": "Host of the specimens:    N - Pig. poultry,  O - Sheep, goats, cattle,  Q - Sheep, goat, cattle", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2004>4>c", "subject": "Agricultural Science Practical", "year": "2004", "type": "Practical", "sub_label": "c", "group": "", "topic": "PARASITES", "question": "Name four economic importance of each of specimens N and Q", "images": [], "marking_scheme": "Economic importance of the specimens on their host:    Specimen N:    The life organism causes  reduced growth rate of animals  loss of appetite in animals  weakness and unthriftness  loss in weight/emaciation/reduced product yield  damages body tissues during the migration of young worms  animal may die from heavy infestation.    Specimen Q:    The life organism causes:  loss of blood leading to anaemia  loss in weight/emaciation  reduced growth rate  reduced milk yield  unthriftness/weakness/loss of condition  increased feed consumption without a corresponding weight gain  poor meat quality", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2004>4>d", "subject": "Agricultural Science Practical", "year": "2004", "type": "Practical", "sub_label": "d", "group": "", "topic": "PARASITES", "question": "State four control measures for specimen O.", "images": [], "marking_scheme": "Control measures for specimen O.    rotational grazing  burning of infested pastures  dipping in acaricides  spraying with acaricides  handpicking  dusting  introducing predators e.g. cattle egrets/biological control.", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2005>1>a>i", "subject": "Agricultural Science Practical", "year": "2005", "type": "Practical", "sub_label": "i", "group": "", "topic": "AGRICULTURAL ECOLOGY : ROCK FORMATION", "question": "Classify specimens B and D according to their mode of formation.", "images": [], "marking_scheme": "Classification of specimens B and D according to their mode of formation are as follows:    B - Sedimentary rock  D - Igneous rock", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2005>1>a>ii", "subject": "Agricultural Science Practical", "year": "2005", "type": "Practical", "sub_label": "ii", "group": "", "topic": "AGRICULTURAL ECOLOGY : ROCK FORMATION", "question": "Name two other rocks for each mode of formation", "images": [], "marking_scheme": "Other examples of each rock types are:    B - Limestone, shale, coal, common salt, gypsum, breccia, conglomerate.  D - Basalt, gabro, diorite, pumice", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2005>1>b", "subject": "Agricultural Science Practical", "year": "2005", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ECOLOGY : ROCK FORMATION", "question": "Given three differences between specimens B and D", "images": [], "marking_scheme": "Differences:    B has layers/ stata while D does not have layers.  Particles are loosely held together in specimen B but not so in specimen D.  Particles in specimen B are fine while those in D are coarse.  Specimen B is lighter than specimen D.  B is prone to erosion while D is resistant to.  B is fairly soft while D is hard.  D is crystaline while B is not.  B is fossilized while D is not.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2005>1>c", "subject": "Agricultural Science Practical", "year": "2005", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ECOLOGY : ROCK FORMATION", "question": "State three uses of specimen D in agriculture.", "images": [], "marking_scheme": "Uses of specimen D in agriculture are:    In control of erosion.  Building farm structures.  For decorations (external and interior).  Farm road construction.  Grinding/sharpening farm tools.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2005>1>d", "subject": "Agricultural Science Practical", "year": "2005", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ECOLOGY : ROCK FORMATION", "question": "State five disadvantages of an abundance of specimen D on a farmland.", "images": [], "marking_scheme": "Disadvantages of abundance of specimen D on a farmland;    Increase coast of tillage operations.  Predisposes man and animals to injury.  Reduces amount of arable land.  Implements wear out fast.  Increases drudgery.  Hideout for reptiles and rodents.  Prevents root penetration.  Makes tillage operations difficult.  Disturbs the growth of plants.  Tends to increase ambient temperature during hot season.  Hinders the activities of micro and macro-organisms.", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2005>2>a", "subject": "Agricultural Science Practical", "year": "2005", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "Name three other equipment that can perform similar functions as specimen F.", "images": [], "marking_scheme": "Other equipment that can perform similar functions as specimen F are:    Motorized sprayer.  Electrodyn sprayer.  Boom sprayer.  Hand sprayer.  Uitra low volume sprayer.  Tractor-mounted / helicopter / aeroplane - mounted sprayer.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2005>2>b", "subject": "Agricultural Science Practical", "year": "2005", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "State five safety precautions to be taken when using specimen F.", "images": [], "marking_scheme": "Safety precautions to be taken when using specimen F:    Ensure the equipment is in good condition before starting.  Read and follow instructions on the chemical container before operations begin.  Wear protective clothing when spraying.  Avoid smoking, eating or drinking while spraying.  Do not blow blocked nozzles with mouth.  Do not spray against the wind.  Avoid walking/spraying into areas freshly sprayed.  Do not spray in hot afternoons.  Wash body thoroughly after use.  Avoid spillage of chemícal in wrong place", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2005>2>c", "subject": "Agricultural Science Practical", "year": "2005", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "Describe how specimen F is used", "images": [], "marking_scheme": "How specimen F is used:    Pour a measured quantity of water into tank.  Add correct amount of chemical to water in tank and miss well.  cover the tank properly with the lid.  Pump to raise pressure within tank.  Mount sprayer on the back.  Spray while walking away from sprayed area.  Direct nozzle to the area to be sprayed.  Pressure in tank is maintained by occasional pumping.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2005>2>d", "subject": "Agricultural Science Practical", "year": "2005", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "State three faults that may develop in specimen F when in use.", "images": [], "marking_scheme": "Faults that may arise while using specimen F are:    Clogging of nozzles.  Pressure could leak from pressure chamber.  Leakage of chemical from hose or tank.  Hose could rupture.  Nozzle could get dismantled/disorganize.  Pump lever may be broken or faulty", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2005>3>a", "subject": "Agricultural Science Practical", "year": "2005", "type": "Practical", "sub_label": "a", "group": "", "topic": "CROP PRODUCTION : CLASSIFICATION OF CROPS~~CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "Identify each specimen G, H, I, and K.", "images": [], "marking_scheme": "ldentification of specimens:    G = Pepper fruit.  H = Onion bulb,  I = Cotton seeds,  K = Okro", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2005>3>b", "subject": "Agricultural Science Practical", "year": "2005", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PRODUCTION : CLASSIFICATION OF CROPS", "question": "Name two uses of each of specimens G and H.", "images": [], "marking_scheme": "Uses of specimens G and H are:    Specimen G ;    As Spice for food.  As insect repellant in stored foodstuff.  Produce/preservative.  Medicinal uses.  As yolk colourant", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2005>3>c", "subject": "Agricultural Science Practical", "year": "2005", "type": "Practical", "sub_label": "c", "group": "", "topic": "CROP PRODUCTION : CLASSIFICATION OF CROPS", "question": "Name the group of crops to which each of specimens H, I, and K belong.", "images": [], "marking_scheme": "Groups of crops:    H- spice.  I - fibre.  K -vegetable", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2005>3>d", "subject": "Agricultural Science Practical", "year": "2005", "type": "Practical", "sub_label": "d", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "Describe the planting operations for specimen G", "images": [], "marking_scheme": "Planting operations for planting specimen G are:    Clear and plough the land.  Separate seeds from fruits.  Prepare nursery beds.  Plant seeds (about 1 cm deep) in the nursery.  While in nursery, weed, shade, and apply water.  Transplant to the field by removing seedling with a ball of soil around roots after 3-5 weeks.  Transplant in the evening or early in the morning. When well established, apply fertilizer and insecticides if necessary.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2005>3>e", "subject": "Agricultural Science Practical", "year": "2005", "type": "Practical", "sub_label": "e", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "Name two pests of specimen H.", "images": [], "marking_scheme": "Maggots, crickets, cutwarms, eelworms, thrips are pests of specimen H.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2005>4>a>i", "subject": "Agricultural Science Practical", "year": "2005", "type": "Practical", "sub_label": "i", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL REPRODUCTION", "question": "identify specimen M.", "images": [], "marking_scheme": "Specimen M; Reproductive system of a hen or female bird. Oviduct of a hen.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2005>4>a>ii", "subject": "Agricultural Science Practical", "year": "2005", "type": "Practical", "sub_label": "ii", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL REPRODUCTION", "question": "Draw and label specimen M.", "images": ["Agricultural Science Practical/imgs/2005/R9RH37.jpg"], "marking_scheme": "", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2005>4>b", "subject": "Agricultural Science Practical", "year": "2005", "type": "Practical", "sub_label": "b", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL REPRODUCTION", "question": "Explain the role of each of the parts of specimen M you have labeled in carrying out its function.", "images": [], "marking_scheme": "Role of each part in the organ for carrying out its function:    Funnel/infundibulum - Receives ova and site for fertilization of ova.  Magnum - Albumin or egg white on yolk chalaza produced.  Isthmus - Secretes materials for shell membranes, determines shape of egg.  Uterus - Water and minerals are added to albumin, secretes calcium carbonate for egg shell.  Vagina - Site for deposition of sperm - passage for egg.  Cloaca - Complete egg passes from uterus to cloaca where it is expelled.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2006>1>a", "subject": "Agricultural Science Practical", "year": "2006", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT", "question": "Using specimens A, C1, C2, D, E and F; carry out a test of a chemical property of the specimen labelled A and present your report under the following headings:    (i) aim (ii) procedure (iii) observaton (iv) conclusion", "images": [], "marking_scheme": "(i) Aim: To determine soil PH/Reaction/aciditylalkaliníty.    (ii) Procedure: Wash a beaker and rinse using distilled water. Put some quantity of specimen A into the beaker, Add some water into specimen A in the beaker. Stir the Content of the beaker very well. Place on the table for few minutes. Dip the two litmus papers into the soil solution one at a time. Observe the change in colour of the litmus paper.    (iii) Observation: Red litmus changed to blue. Blue litmus remained unchanged.    (iv) Conclusion: The soil is alkaline/basic in nature.", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2006>1>b", "subject": "Agricultural Science Practical", "year": "2006", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT", "question": "State two probable causes of the soil condition observed on Specimen A", "images": [], "marking_scheme": "Probable reasons for the observed soil condition:    Continuous alkaline fertilizer addition e.g. Potash.  Chemical composition of parent rock.  Over liming.  Arid condition.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2006>1>c", "subject": "Agricultural Science Practical", "year": "2006", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ECOLOGY : MEANING AND IMPORTANCE OF AGRICULTURAL ECOLOGY", "question": "State four reasons why the experiment is important in agriculture.", "images": [], "marking_scheme": "Agricultural Importance of the Experiment:    Enables farmers to determine soil PH.  Type of crop to grow depends on the determined soil PH.  Soil PH affects the survival of soil microbes.  Soil PH affects the growth of planktons in fish ponds.  Soil PH controls the availability of some soil plant nutrients.  Helps in determining the fertilizer type to apply.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2006>2>a", "subject": "Agricultural Science Practical", "year": "2006", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "Diagrams H and I illustrate tractor-coupled implements. Use them to answer questions (a) - (c)    Identify the implements illustrated by diagrams H and I", "images": [], "marking_scheme": "ldentification:    H - Disc plough.  I - Mouldboard plough.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2006>2>b", "subject": "Agricultural Science Practical", "year": "2006", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "Name the parts labelled I -X.", "images": [], "marking_scheme": "I. Point of attachment to the tractor/coupling point.   II. Beam/Frame.  III. Scrapper  IV. Disc  V. Furrow wheel/rear-wheel  VI. Leg/standard  VII. Coulier  VIII. Share  IX. Mouldboard  X. Standard/leg", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2006>2>c", "subject": "Agricultural Science Practical", "year": "2006", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "State one function of each or parts labelled I -IX.", "images": [], "marking_scheme": "Provides the point of attachment to the tractor.  Holds the discs in position/used to increase depth of penetration.  Removes soil that clings to the disc during operation.  Makes horizontal and vertical cuts of the soil/cutting and inverting soil.  Provides balancing effect for the plough/ enables the plough to jump over stones or stumps.  Attaches the disc to the beam.  Makes vertical cuts/furrows.  Makes horizontal cuts.  Turns the soil over/buries weeds.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2006>3>a", "subject": "Agricultural Science Practical", "year": "2006", "type": "Practical", "sub_label": "a", "group": "", "topic": "CROP PRODUCTION : CLASSIFICATION OF CROPS", "question": "Name the primary source of each of specimens J (SAW DUST) and L", "images": [], "marking_scheme": "Primary Source of Specimen J and L: Both are obtained from wood/forest trees/timber.", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2006>3>b", "subject": "Agricultural Science Practical", "year": "2006", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PRODUCTION : CLASSIFICATION OF CROPS", "question": "State four uses of each of specimens J and K(PIECE OF PLANK), and two uses of specimen M (HONEY).", "images": [], "marking_scheme": "Uses of Specimens J. K and M:    Specimen J (Saw dust):    Making particle boards/ceiling boards.  Source of fuel/ smoking fish.  As poultry litter.  Source of potash when burnt to ashes.  As organic matter for the soil.  Mulch material  Bedding material for young animals  Planting medium in seed boxes.  Packaging breakable products  Specimen K(Piece of plank);    For constructing farm building,  For making tuniture;  Component of agricultural tools eg handles of knife, cutlass, dibber etc  Source of fuel;  Packaging of agricultural produce;  For paper production  Constructing farm structures e.g. cribs, paddocks, pens, hutches  Making blackboards for schools  Construction of boats/canoes/paddle.  Specimen M (Honey);    As food for human/sweeteners/sugar.  For medicinal purposes  healing wounds/burns  For the production of cosmetic products  For pharmaceutical purposes/industrial raw material.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2006>3>c", "subject": "Agricultural Science Practical", "year": "2006", "type": "Practical", "sub_label": "c", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "State three ways of ensuring continuous supply of the primary source of specimen K", "images": [], "marking_scheme": "Ensuring continuous supply of timber;    Planting seedlings of suitable forest trees species.  Prevention of bush forests.  Selective exploitation/exploration.  Practise taungva System in places with land scarcity.  enforcement of forestry, regulation/policing of forests  Promote regeneration of stumps by discouraging complete removal of stumps  Discouraging the use of firewoods for domestic cooking by developing alternatives.  Distributing the seedings of early-maturing species to farmers", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2006>4>a", "subject": "Agricultural Science Practical", "year": "2006", "type": "Practical", "sub_label": "a", "group": "", "topic": "ANIMAL PRODUCTION : AQUACULTURE", "question": "ldentify specimens N, O, and P.", "images": [], "marking_scheme": "identification of Specimens:    N - Water lettuce  O - Cat Fish,  P - Tilapia spp.", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2006>4>b", "subject": "Agricultural Science Practical", "year": "2006", "type": "Practical", "sub_label": "b", "group": "", "topic": "ANIMAL PRODUCTION : AQUACULTURE", "question": "State the relationship between specimens O and P.", "images": [], "marking_scheme": "Relationship between Catfish and Tilapia Spp: Catfish feeds on the fries/fingerlings of tilapia spp. OR Specimen O (Catfish) helps to control the population of specimen. Predator-prey relationship.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2006>4>c", "subject": "Agricultural Science Practical", "year": "2006", "type": "Practical", "sub_label": "c", "group": "", "topic": "ANIMAL PRODUCTION : AQUACULTURE", "question": "List five economic importance of specimen N in an aquatic ecosystem,", "images": [], "marking_scheme": "Economic Importance of Specimen N in an aquatic ecosystem:    Hinders free movement of aquatic organisms.  Limits the penetration of light into ponds.  Hinders proper aeration.  Takes nutrients from the pond that could have been used by the planktons.  Hides fishes from being sighted by predators.  Some herbivorous fish feed on it. Interferes with fish harvesting.  Competes with fish for dissolved oxygen for root respiration.  Provides breeding ground for some fish species.  Increases cost of production of fish.  Makes navigation difficult.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2006>4>d", "subject": "Agricultural Science Practical", "year": "2006", "type": "Practical", "sub_label": "d", "group": "", "topic": "ANIMAL PRODUCTION : AQUACULTURE", "question": "Give three benefits of stocking both specimens O and P together in the same pond.", "images": [], "marking_scheme": "Ways of Controlling Specimen N:    Physical removal by hand (manual).  Remove it consistently/mechanically.  Stock an adequate number of herbivorous fishes.  Lime the pond properly before stocking.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2007>1>a", "subject": "Agricultural Science Practical", "year": "2007", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT", "question": "Study carefully the experimental set-ups labelled A, B and C.    What is the aim of the experiment for which the apparatus has been set up?", "images": [], "marking_scheme": "The aim of the experimental setup is:    (i) To compare/determine the amount/level of the capillarity attraction of different types of soils     (ii) To compare the capillary movement of water in different soil types.", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2007>1>b", "subject": "Agricultural Science Practical", "year": "2007", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT", "question": "List the experimental set-ups in the order in which water has risen through the soil samples, starting with the highest", "images": [], "marking_scheme": "The rise in water is in the following order;    Specimen C - Highest - Sand  Specimen A - Higher - Loam  Specimen B - Lowest - clay. (Note: These levels are what may be observed within the time limit given for the experiment. If longer the levels would change.)", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2007>1>c", "subject": "Agricultural Science Practical", "year": "2007", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT", "question": "List six items of apparatus used in the experimental set-up.", "images": [], "marking_scheme": "Apparatus used in the experimental setup:    (i) A large beaker/basin/dish/trough    (ii) Three capillary tubes/glass tubes.    (iii) Soil samples A, B, and C.    (iv) Water    (v) Cotton wool    (vi) Clamps    (vi) Retort stands.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2007>1>d", "subject": "Agricultural Science Practical", "year": "2007", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT", "question": "Describe briefly the procedure used in setting up the experiment.", "images": [], "marking_scheme": "Description of the procedure used in setting up the experiment:    (i) Take three glass tubes and plug each with cotton wool at one end.    (ii) Dry the soil samples and break up the lumps into smaller particles/or grind.    (iii) Fill each tube with equal quantíties of dry samples of clayey, loamy and sandy soils.    (iv) Fix the three tubes in an upright position with clamps.    (v) Get the three glass tubes immersed in a trough of water.    (vi) Allow to stand for the required time.    (vii) Watch the upward movement of water into the soil samples and record your observation.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2007>1>e", "subject": "Agricultural Science Practical", "year": "2007", "type": "Practical", "sub_label": "e", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT", "question": "Why is there a difference in the water levels of the soil samples in the set ups labelled B and C?", "images": [], "marking_scheme": "Why there is a difference in the water levels in soil samples B and C:    (i) In sample C. sand the larger particles and pore spaces allow water to rise much faster than in clay (sample B) but stop soon because of low capillary attraction.    (ii) In sample B, clay, the very fine particles and pore spaces do not allow water to penetrate and rise fast, but as the clay particles absorb water and swell, there is greater capillarity attraction which enables the level to rise up more than sand later.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2007>2>a", "subject": "Agricultural Science Practical", "year": "2007", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING", "question": "Study the diagrams below and use them to answer questions (a) to (c).      ldentify the equipment illustrated by diagrams D, E, F, and G.", "images": ["Agricultural Science Practical/imgs/2007/GA9CWL.jpg"], "marking_scheme": "ldentification of equipment D to G:    D = Gunter's chain;  E = Cross staff;  F = Prismatic compass;  G = Theodolite.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2007>2>b", "subject": "Agricultural Science Practical", "year": "2007", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING", "question": "State the farm operation for which the equipment illustrated by diagrams D,E,F and G.", "images": [], "marking_scheme": "Farm operation for which the equipment are generally used:    They are all survey equipment or used for farm surveying", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2007>2>c", "subject": "Agricultural Science Practical", "year": "2007", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING", "question": "Enumerate two specific uses of each of the equipment illustrated by diagrams F and G.", "images": [], "marking_scheme": "Use of equipment F and G:    F - Prismatic compass;    Assisting in locating baseline or places.  Taking direction with reference to the magnetic meridian.  G-Theododite:    Measuring horizontal and vertical angles.  Triangulation in chain survey of plane.  Rectangular coordinates for location of points.  Determines elevation.  Location or sighting of station.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2007>2>d", "subject": "Agricultural Science Practical", "year": "2007", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING", "question": "State six general ways of maintaining the equipment illustrated by diagrams F and G.", "images": [], "marking_scheme": "Ways of maintaining equipment F and G:    Clean or wash and dry properly as appropriate after use.  Grease/oil the necessary metal parts.  After use, ensure that the screws, bolts, and nuts are properly secured.  Protect the equipment from getting wet particularly specimen G.  Use the equipment according to manufacturer's instructions.  After use and cleaning store in cool dry place.  Keep the prismatic compass away from the magnetic field.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2007>3>a", "subject": "Agricultural Science Practical", "year": "2007", "type": "Practical", "sub_label": "a", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "Observe specimens H, l, J, and K carefully.    State one method of propagation of each of the specimens", "images": [], "marking_scheme": "Method of propagation of the specimens:    Specimen H- stem cutting.  Specimen I- seed yam or yam seeds,  Specimen J - tuber, stem cutting/vine.  Specimen K - rhizome.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2007>3>b", "subject": "Agricultural Science Practical", "year": "2007", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "State four advantages of staking the crop which specimen I is obtained.", "images": [], "marking_scheme": "Advantages of staking in the production specimen I (Yam tuber):    Staking is essential for good yields.  Stakes give support to the climbing vines.   Exposes the leaves for good interception of sunshine/photosynthesis.  Minimizes damage to the vine  Creates more room for farmer to carry out cultural practices.  Good air circulation.  Permits easy movement of the farmer in the farm.  Prevents transmission of soil pathogens to leaves through rain splash.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2007>3>c", "subject": "Agricultural Science Practical", "year": "2007", "type": "Practical", "sub_label": "c", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "Name the toxic substance present in specimen H and give two methods of reducing it", "images": [], "marking_scheme": "Toxic substance present in specimen H:    HCN/Cyanogenetic glycoside/prussic acid.  Methods or reducing the toxic substance    Boiling  Sun-drying  Fermentation  Grating  Frying  Roasting  Soaking", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2007>3>d", "subject": "Agricultural Science Practical", "year": "2007", "type": "Practical", "sub_label": "d", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "Describe the processing of specimen H into garri.", "images": [], "marking_scheme": "Description of the processing of specimen H into garri:    Get raw cassava tubers.  Peel the tubers with knife  Wash the peeled tubers  Grate the peeled tubers with a grater  Put the grated cassava into sacks  Screw press or ferment the grated tubers for 3 days  Sift the fermented material  Fry the fermented material into garri  Sift the fried garri again into fine or coarse forms  Bag the garri", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2007>4>a", "subject": "Agricultural Science Practical", "year": "2007", "type": "Practical", "sub_label": "a", "group": "", "topic": "ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT", "question": "State a breed of specimen L which may be used for only commercial egg production.", "images": [], "marking_scheme": "Breeds of Specimen L which may be used for only commercial egg production:    White Leghorm  Black leghorm  Ancona  Grey dorking  Red sussex  Minorca.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2007>4>b", "subject": "Agricultural Science Practical", "year": "2007", "type": "Practical", "sub_label": "b", "group": "", "topic": "ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT", "question": "How long does it take an improved specimen L from day old to reach its point of lay", "images": [], "marking_scheme": "Maturity períod of specimen L from day old to point of lay is 18-20 (plus or minus one) weeks.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2007>4>c", "subject": "Agricultural Science Practical", "year": "2007", "type": "Practical", "sub_label": "c", "group": "", "topic": "ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT", "question": "Name any four features on the head of specimen L.", "images": [], "marking_scheme": "Features on the head of specimen L are:    Comb  Wattles  Nostril  Eyes  Beak  Ear lobe.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2007>4>d", "subject": "Agricultural Science Practical", "year": "2007", "type": "Practical", "sub_label": "d", "group": "", "topic": "ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT", "question": "Mention three parasites and four diseases that attack specimen L", "images": [], "marking_scheme": "Parasites that attack Specimen L include:    Flea  Mite  Roundworms  Ticks  Lice.  Diseases that attack specimen L are:    Typhoid  Cholera  Fowl pox  Diptheria  Newcastle  Coccidiosis  Gumboro  Aspergillosis  Chroníc Respiralory Disease (CRD),  Pullorum  Marek's  Salmonellosis  Bird Flu/Avian influenza.", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2007>4>e", "subject": "Agricultural Science Practical", "year": "2007", "type": "Practical", "sub_label": "e", "group": "", "topic": "ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT", "question": "Mention two ways of controlling the parasites mentioned in 4(d) above", "images": [], "marking_scheme": "Ways of controlling the mentioned parasites:    Periodic dusting or bathing of birds with recommended insecticide powder or appropriate chemical.  Dusting/spraying of chicken pen using appropriate pesticide.  Keeping chicken pens clean/farm sanitation.  Deworm with anthelmintics.  lsolation of infected birds.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2008>1>a", "subject": "Agricultural Science Practical", "year": "2008", "type": "Practical", "sub_label": "a", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "What class of manure do each of specimens A (POULTRY DROPPINGS) and B (N-P-K 15-15-15) belong to?", "images": [], "marking_scheme": "Class of Manure:    Specimen A; -Organic manure  Specimen B - Inorganic manure", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2008>1>b", "subject": "Agricultural Science Practical", "year": "2008", "type": "Practical", "sub_label": "b", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "List three characteristics of each of specimens A and B.", "images": [], "marking_scheme": "Characteristics of;     specimen A (Poultry droppings)    it is bulky .  Rick in micro-organisms .  Contains many plant nutrients/improves soil fertility  The nutrient concentrations are fairly low  Capable of binding soil particles together / improves soil structure  Has a bad smell Improves soil temperature  It is structureless/amorphous  Tends to be neutral in reaction  Low availability of nutrients  Nutrients not easily leached/lasts longer in the soil Reduces soil erosion by improving soil structure  Variable nutrient concentration  Specimen B (N-P-K 5-15);    Granular in structure  Has pungent smell  Contains only few mineral nutrients  The concentrations of these nutrients are high  The nutrients are fixed in definite proportion  Not bulky in nature  Easily leached; does not last long in the soil  Does not reduce soil erosion  Nutrients are readily available  Hygroscopic", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2008>1>c", "subject": "Agricultural Science Practical", "year": "2008", "type": "Practical", "sub_label": "c", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "List two precautions to be observed when applying each of specimens A and B.", "images": [], "marking_scheme": "Precautions to take when applying:    Specimen A (poultry droppings) -    Should not be applied when fresh to crops on the field  Must not be allowed to touch the plants  Should cure properly before application/fully decomposed before applying  Wash hands immediately after application  Wear protective clothing  Should be applied when soil is wet  Specimen B (N-P-K 15-15-15) -    Do not allow direct contact with the plant  Do not apply when the soil is very dry  When applying manually always wear gloves  Wash hands immediately after application  Do not apply to alkaline soils  Do not eat, drink or smoke when applying the fertilizers  Remove all ornamentals from the body  Do soil test to know deficient nutrients before applying", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2008>1>d", "subject": "Agricultural Science Practical", "year": "2008", "type": "Practical", "sub_label": "d", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "State which of the specimens is recommended to improve clay soil. Give two reasons for your answer.", "images": [], "marking_scheme": "Specimen recommended to improve clay soil is - Specimen A (Poultry droppings)    Reasons:    It binds clayey particles together thus opening up / enlarging the pores  lt improves water percolation  lt improves aeration  It improves soil fertility  It improves oil drainage  lt will improve soil temperature in clay soils  It will enhance the release of locked nutrients and make them more available.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2008>2>a", "subject": "Agricultural Science Practical", "year": "2008", "type": "Practical", "sub_label": "a", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT", "question": "The diagrams below represent two modern equipment used in commercial animal production. Use them to answer question (a), (b) and (c).       ldentify the equipment labelled C and D.", "images": ["Agricultural Science Practical/imgs/2008/XXNFLX.jpg", "Agricultural Science Practical/imgs/2008/CD424D.jpg"], "marking_scheme": "ldentification of equipment labelled;    C- Incubator,  D- Milking machine", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2008>2>b", "subject": "Agricultural Science Practical", "year": "2008", "type": "Practical", "sub_label": "b", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT", "question": "The diagrams below represent two modern equipment used in commercial animal production. Use them to answer question (a), (b) and (c).     Name the parts labelled I to VIl in diagrams C and D.", "images": ["Agricultural Science Practical/imgs/2008/XXNFLX.jpg", "Agricultural Science Practical/imgs/2008/CD424D.jpg"], "marking_scheme": "Labelling of Parts of the two equipment;    I - Thermometer  II - Egg  Ill - Egg tray  IV - Water  V - Source of heat  VI - Teat cup  VII. Source of power/Generator/Vacuum pump", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2008>2>c", "subject": "Agricultural Science Practical", "year": "2008", "type": "Practical", "sub_label": "c", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT", "question": "The diagrams below represent two modern equipment used in commercial animal production. Use them to answer question (a), (b) and (c).     State three precautions to be observed when using each of the two equipment", "images": ["Agricultural Science Practical/imgs/2008/XXNFLX.jpg", "Agricultural Science Practical/imgs/2008/CD424D.jpg"], "marking_scheme": "Precautions to be observed when using;    C: Incubator -    Only fertile eggs should be set and retained in the incubator  Eggs must be clean  No washing of eggs with water (because this tends to Increase the porous nature of the egg thereby increasing the respiration of the embryo)  Eggs must be fresh; that is, they should not be stored for more than two weeks prior to their journey to the incubator.  Eggs must be disinfested at least three to four (3-4) hours before arranging them in the incubator  Arrange eggs such that the air space end is up  Uniformly sized eggs should be set  Monitor the temperature inside the incubator  Ensure adequate exchange of gases in the incubator  Set the incubator away from the walls for proper ventilation  The Relative Humidity must be constantly monitored.  B: Milking Machine -    The udder should be cleaned thoroughly before milking  The foremilk should be tested with test cup  The milker should concentrate when milking  The dairy animal should be treated with care, that is, handled gently; i.e. apply little pressure to the udder.  The handlers should not be distracted in any form like smoking or drinking while milking.  Use slightly warm water to wash/scrub the udder/teats  Avoid any form of noise during milking  Introduce some feed to the milking animal  Supply light, gentle music to further induce the animal to let down milk.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2008>3>a", "subject": "Agricultural Science Practical", "year": "2008", "type": "Practical", "sub_label": "a", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "Identify specimens E, F. G and H.", "images": [], "marking_scheme": "ldentification of specimens:    E - Maize weevil  F - Cotton Stainer bug/Dysdercus  G - Termite  H - Grasshopper", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2008>3>b", "subject": "Agricultural Science Practical", "year": "2008", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "Name the part of the plant usually attacked by each of specimens E, F, G, and H.", "images": [], "marking_scheme": "Part of Plant attacked by specimens    E - Maize grains  F - Cotton bolls/okro fruits/akee apple  G - Crop stems/roots/grains of lodged cereals  H - Plant leaves and young shoots", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2008>3>c", "subject": "Agricultural Science Practical", "year": "2008", "type": "Practical", "sub_label": "c", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "Give two ways by which each of the specimens damages crops.", "images": [], "marking_scheme": "Damages caused to crops;    Specimen E (Maize Weevil);    Bores into the grains of maize and creates holes  Destroys the embryo and hence prevents germination  Eats the endosperm and reduces food value  Vents serve as sites for secondary infections  Specimen F (Dysdercus/cotton stainer bug);    Pierces into mature cotton bolls/okro fruit/akee apple  Stains the cotton lint  Vents created serve as sites for secondary infection  Prevents good fruit formation in okro  Causes premature drop of fruits  Specimen G (Termite);    Chews the stem and roots of plants and tubers  Weakens the stem and roots of plants and make them to lodge  Destroys seed grains lying on the field  Also creates tunnels for secondary infection  Specimen H (Grasshopper) ;    Causes defoliation of crops  Young shoots are destroyed  Wounds left on the crops can serve as vents for secondary infection  Buds are also destroyed  Reduces the photosynthetic ability of crop plants  Reduces the growth of crop plants", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2008>3>d", "subject": "Agricultural Science Practical", "year": "2008", "type": "Practical", "sub_label": "d", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "State three methods of controlling specimen E.", "images": [], "marking_scheme": "Methods of Controlling specimen E (Maize Weevil);    Dry grains very well before storing  Harvest early soon after drying  Store grains in air-tight containers/hermetic storage  Apply pesticides to the grains before storage  Fumigate storage facilities  Use smoke to kill or ward off the weevils  Store grains in hot dried pepper/neem extracts", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2008>4>a", "subject": "Agricultural Science Practical", "year": "2008", "type": "Practical", "sub_label": "a", "group": "", "topic": "ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS", "question": "ldentify specimens l, J, and K.", "images": [], "marking_scheme": "ldentification of Specimens    Specimen I - Piece of liver  J - Piece of ruminant skin  K - Piece of rumen/part of ruminant", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2008>4>b", "subject": "Agricultural Science Practical", "year": "2008", "type": "Practical", "sub_label": "b", "group": "", "topic": "ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS", "question": "State three functions of each of specimens I, J and K to the animal.", "images": [], "marking_scheme": "Functions of Specimens:    I (Liver) -    Manufactures blood proteins  Stores vitamins  Secretes bile  Detoxifies poisonous substances  Destroys old red blood cells  Metabolizes nutrients - carbohydrates, proteins, etc./ deamination of amino acids  Stores iron Storage of glycogen/regulation of blood sugar / excess carbohydrate  Also stores large quantity of blood    Regulates body temperature through metabolism of nutrient  Storage of iron  Synthesis of enzymes  J (Skin);    Prevention of entry into body of dangerous substances  Mechanical protection of the body  Protection of body from irradiation sun rays  Involved in the thermoregulation  Enables animals to have sensation of touch, pain, heat or cold/response to stimuli  Secretes oil that lubricates the skin  Vitamin D3 synthesis with the aid of sunlight  Storage of excess fat  Promotion of milk since the udder is modified skin  Insulation against cold and unfavourable weather condition  Secretion of sweat / excretion  K(Rumen);    Mechanical breakdown of coarse fibrous feeds into smaller particles  Involved in the digestion of fibrous feed by  Vitamin B synthesis  Absorption of Volatile Fatty Acids  Fermentation of carbohydrate substances into simpler Compounds  Storage of hurriedly ingested feed for further digestion later (rumination)  Low-quality proteins are converted to higher quality proteins inside the rumen  Propulsion of ingested feed into other stomach compartments  Harbours millions of microbes which are fibre digestion.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2008>4>c", "subject": "Agricultural Science Practical", "year": "2008", "type": "Practical", "sub_label": "c", "group": "", "topic": "ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS", "question": "Name the process marks in preserving fresh quantity of specimen L", "images": [], "marking_scheme": "Process of Preserving specimen L (Milk); Pasteurization", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2008>4>d", "subject": "Agricultural Science Practical", "year": "2008", "type": "Practical", "sub_label": "d", "group": "", "topic": "ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS", "question": "Give five products that can be produced from specimen L (MILK).", "images": [], "marking_scheme": "Products that can be produced from specimen L (Milk)     Whey  Cheese  lce cream  Casein  Condensed/Canned milk  Curd  Butter scotch  Butter from milk fat  Dried milk powder  Yoghurt", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2009>1>a", "subject": "Agricultural Science Practical", "year": "2009", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "ldentify specimens A, B, and C.", "images": [], "marking_scheme": "identification of specimen A, B and C;    Specimens A ; Sandy soil  B ; Clayey soil  C; Earthworm", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2009>1>b", "subject": "Agricultural Science Practical", "year": "2009", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "In a tabular form, compare three physical characteristics of specimens A and B.", "images": [], "marking_scheme": "Specimen A (Sandy soil)Specimen B (Clayey soil)It is coarse - grainedIt is fine grainedIt is grittyIt is smooth to the touchLow capillarity actionCapillarity is very highHigh percolation ratePercolation is lowLeaching is highNot easily leachedIt easily gets hot and coldIt does not easily get hot and coldIt is not sticky when wetWhen wet it is highly stickyLow plasticity/cannot be moulded into any shapeIt can be moulded into any shape/high plasticityHas low water-holding capacityHigh water-holding capacityIt is well-drained and aeratedClayey soils are poorly drained and poorly aeratedHas large pore spacesHas small/fine pore spaces Easy to workDifficult/heavy to work", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2009>1>c>i", "subject": "Agricultural Science Practical", "year": "2009", "type": "Practical", "sub_label": "i", "group": "", "topic": "AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "Which of specimens A and B would you recommend for pond construction?", "images": [], "marking_scheme": "Specimen recommended for pond construction: Specimen B/Clayey", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2009>1>c>ii", "subject": "Agricultural Science Practical", "year": "2009", "type": "Practical", "sub_label": "ii", "group": "", "topic": "AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "Give one reason for your answer in (c)(i).", "images": [], "marking_scheme": "Reason;    Because it has very good water holding capacity  Does not lose water through percolation easily", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2009>1>d", "subject": "Agricultural Science Practical", "year": "2009", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "List two ways of improving specimen A for crop production.", "images": [], "marking_scheme": "Ways of improving specimen A (Sandy soil)    Mulching  Planting of cover crops/Green manuring  Liming  Fallowing", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2009>1>e", "subject": "Agricultural Science Practical", "year": "2009", "type": "Practical", "sub_label": "e", "group": "", "topic": "AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "State two ways by which specimen C is of economic importance in agriculture.", "images": [], "marking_scheme": "Ways by which specimen C (Earthworm) is of economic importance in agriculture    Helps to increase water infiltration and percolation.  It burrows into the soil thereby helping to loosen the soil for easy root penetration.  Helps in soil aeration.  During feeding, the earthworms drag plant remains and leaves into the soil, thereby improving soil fertility improves crop yields.  Helps in soil formation  helps in mixing the soil  It increases the organic matter content of the soil.  Helps to improve soil structure.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2009>2>a", "subject": "Agricultural Science Practical", "year": "2009", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "For each of specimens H (SPADE), l (SECATEURS) and J (OPEN ENDED SPANNER) name two farm tools that can perform functions similar to those of the specimens.", "images": [], "marking_scheme": "Tools that can perform similar functions as; specimens H, l, and J    Specimen H (Spade) - Hoe, shovel, and hand trowel  Specimen I (Secateurs) - Saw, sickle, cutlass, and shears  Specimen J (Open ended spanner)-Wrench, ring spanner and pliers.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2009>2>b", "subject": "Agricultural Science Practical", "year": "2009", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "Describe how each of specimens I and J is used.", "images": [], "marking_scheme": "Description of how specimen I (Secateurs) is used -    Open the handle to widen the blades.  Fix the opened blades against the material to be cut.  Release the handle  Press back the handles to close the blades and cut the materials.  Description of how specimen J (Open-ended spanner) is used    Fix the opened end directly on top of the bolt (appropriate size).  Turn the handle clockwise (to tighten) or anti-clockwise (to loosen) the bolt.  continue to turn until the bolt is firmly fixed or loosened before releasing the handle.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2009>2>c", "subject": "Agricultural Science Practical", "year": "2009", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "Describe each of specimens H and J.", "images": [], "marking_scheme": "Description of each of specimens H and J Specimen H (Spade)    Has a long wooden/metallic handle.  Blade is metalic (steel)  Blade is rectangular, flat and sharp at one end for each penetration into the soil.  Handle widens at the posterior end to form a triangular block or \"D\" shape for firm handling.  Specimen J (Open-ended spanner)    It is metallic.  Both sides end in a hexagonal shape of various sizes that fit the heads of bolts.  Flattened metallic handle.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2009>2>d", "subject": "Agricultural Science Practical", "year": "2009", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "Enumerate four advantages of using farm tools for farm work.", "images": [], "marking_scheme": "Advantages of using farm tools for farm work    Minimize injury to the farmer.  Make work easier/minimize drudgery.  Enhance faster completion of operation/saves time.  Increase farmers' productivity.  Enhance certain operations, e.g. budding.  Not expensive to acquire.  They are sometimes the only way to get certain operations done on the farm.  Easy to operate and requires no high technical know-how.  Can be operated at all times.  Easy to maintain.  Do not require any specialized sources of power to operate.", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2009>3>a", "subject": "Agricultural Science Practical", "year": "2009", "type": "Practical", "sub_label": "a", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "Identify specimens K and L.", "images": [], "marking_scheme": "ldentification of specimens K and L    Specimen K- Rhinoceros beetle  Specimen L - Rat", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2009>3>b", "subject": "Agricultural Science Practical", "year": "2009", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "List three crops commonly attacked by each of specimens K and L", "images": [], "marking_scheme": "Crops commonly attacked by specimens K and L    Specimen K (Rhinoceros beetle)    Oil palm  Rafia palm  Coconut plam  Yam  Cocoyam  Banana    Specimen L- Rat    Cassava  Vegetables  Oil palm  Groundnut  Banana  Yam/cocoyam/sweet potatoes  Cereal grains (stored or field)", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2009>3>c", "subject": "Agricultural Science Practical", "year": "2009", "type": "Practical", "sub_label": "c", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "State three types of damage to crops caused by each of specimens K and L.", "images": [], "marking_scheme": "Damage caused by specimens K and L beetle Damage caused by specimen K (Rhinoceros    Burrows into farm produce.  Reduces the quality of farm produce.  Burrows into the developing spear of the oil palm or other palms.  Damages the growing point of young palms  Wounds serve as entry points for secondary infection  May cause young plants to break/fall/lodge.  Damage caused by specimen K (Rat);    Eats young plants such as young oil palm, Cereals, and groundnuts.  Destroys the roots of crops when it burroWs and causes them to lodge.  Eats up roots and tubers of crops.  Eats up vegetables on the farm.  Reduces the quality of produce.  Wounds serve as entry points for secondary infection  Contaminates produce with faeces and urine.  Reduces yields of crops.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2009>3>d", "subject": "Agricultural Science Practical", "year": "2009", "type": "Practical", "sub_label": "d", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "Mention two ways of controlling each of specimens K and L", "images": [], "marking_scheme": "Ways of controlling specimen K (Rhinocerous beetle) and L (Rat)    Control of specimen K (Rhinocerous beetle);    By hand-picking.  By use of insecticide.  Destroy felled palms and stumps by burning.  Biological - use known natural enemies to control them    Control of specimen L (Rat);    By setting traps.  By using repellents.  Rat-proofing.  By poisoning/use of rodenticides.  Biological - using predators such as cats and dogs.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2009>4>a", "subject": "Agricultural Science Practical", "year": "2009", "type": "Practical", "sub_label": "a", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "ldentify specimens O and P.", "images": [], "marking_scheme": "ldentification of specimen O and specimen P;    Specimen O - Animal horn  Specimen P - Animal skin/animal hide", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2009>4>b", "subject": "Agricultural Science Practical", "year": "2009", "type": "Practical", "sub_label": "b", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "State three farm animals which do not possess specimen O", "images": [], "marking_scheme": "Farm animals which do not possess specimen O (Animal horn)    Poultry  Swine/pig  Rabbit   Guinea pig  Donkey  Horse  Camel", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2009>4>c>i", "subject": "Agricultural Science Practical", "year": "2009", "type": "Practical", "sub_label": "i", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "Name two farm animals in which both sexes possess specimen O.", "images": [], "marking_scheme": "Farm animals in which both sexes possess specimen O (Animal horn)    Cattle  Goats", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2009>4>c>ii", "subject": "Agricultural Science Practical", "year": "2009", "type": "Practical", "sub_label": "ii", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "State one farm animal in which only one sex of the species possesses specimen O.", "images": [], "marking_scheme": "Farm animal in which only one sex of the species possesses specimen O;    Sheep", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2009>4>d", "subject": "Agricultural Science Practical", "year": "2009", "type": "Practical", "sub_label": "d", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "State two functions of each of the specimens O and P to the animals that possess them.", "images": [], "marking_scheme": "Functions of specimen 0 (Animal horn) and Functions of  Specimen P (Animal skin)    Functions of Animal Horn;    For defence.  For attack/offence  For scratching the body.  Enhances the appearance of the animal possessing it.  Functions of Animal skin ;    It manufactures vitamin D, with the aid of sunlight.  Storage of reserved food (fat) under the skin.  For protection of the body organs/insulation.  For temperature regulation of the body.  Excretion through sweating.  Response to environmental stimulus.  Milk secretion through the mammary gland.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2009>4>e", "subject": "Agricultural Science Practical", "year": "2009", "type": "Practical", "sub_label": "e", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "Mention three problems that a farmer may encounter in the management of animals which possess specimen O.", "images": [], "marking_scheme": "Problems a farmer may encounter in the management of animals which possess specimen O (Animal horn)    Problems of space when transporting the animals.  Animal may injure the owner or herdsmen with the horns.  Animal may injure one another with the horns.  Animal may use horns to destroy buildings and Other farm structures.  Animals with horns bully their young ones and those without horns  Requires larger housing space and more pens spaces.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2010>1>a>i", "subject": "Agricultural Science Practical", "year": "2010", "type": "Practical", "sub_label": "i", "group": "", "topic": "AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "Using specimens A, B (WATER), C (SODIUM CARBONATE).and D, carry out an experiment to show that soil is made up of different particle sizes    Describe the procedure used in concting the experiment", "images": [], "marking_scheme": "Description of the procedure used ln conducting the experiment    -Some quantity of soil was weighed  -The soil was put in a 250cm measuring cylinder  -Some water was added to the soil in the cylinder to submerge the soil  -A little quantity of sodium carbonate was added into the cylinder  -A hand was placed over the opening of the cylinder  -The cylinder was then placed on a flat level bench for at least an hour to allow contents settle", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2010>1>a>ii", "subject": "Agricultural Science Practical", "year": "2010", "type": "Practical", "sub_label": "ii", "group": "", "topic": "AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "Using specimens A, B (WATER), C (SODIUM CARBONATE).and D, carry out an experiment to show that soil is made up of different particle sizes  State your observations and results", "images": [], "marking_scheme": "Observations and results -      -The soil fractions settled in layers  -The bigger gravels settled first   -Followed by sand  -And silt and  -Clay  -Colloids remained in suspension  -Humus and organic materials were seen floating  -Depth of each layer was read from the marks on the cylinder.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2010>1>b", "subject": "Agricultural Science Practical", "year": "2010", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "Using specimens A, B (WATER), C (SODIUM CARBONATE).and D, carry out an experiment to show that soil is made up of different particle sizes  State one function of each of specimens B and specimen C in the experiment", "images": [], "marking_scheme": "Function of Specimen B (water) and Specimen C (sodium carbonate) in the experiment     Water (Specimen)     -Provides a medium for dispersing the soil and dissolve the chemical  -Enhances the differential settling of materials  Sodium Carbonate (Specimen C)    -Enhances complete dispersal of soil aggregates/faster  -Makes/renders the reading of the levels/layers easier", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2010>1>c", "subject": "Agricultural Science Practical", "year": "2010", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "Using specimens A, B (WATER), C (SODIUM CARBONATE).and D, carry out an experiment to show that soil is made up of different particle sizes  State three precautions taken in carrying out the experiment.", "images": [], "marking_scheme": "Precautions to take in carrying out the experiment -    -Cover the opening of the cylinder well to prevent spillage when shaking  -Do not add too much sodium carbonate to the soil as that will reduce readability of layers  -Allow sufficient time for content to settle properly  -Place cylinder on a horizontal surface to ensure correct reading  -Avoid error of parallax when reading results  -Enough water should be added to the soil to allow free floatation and sedimentation, otherwise, the experiment will not work.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2010>2>a", "subject": "Agricultural Science Practical", "year": "2010", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "Describe briefly each of specimens G (CUTLASS), H (HOE), and l (SHORT HANDLE SICKLE)", "images": [], "marking_scheme": "Specimen G (Cutlass)    -Has a long and flat metal blade  -One edge of the metal blade is sharp while the other edge is blunt  -Has a short wooden/rubber/metal handle at one end of the blade    Specimen H (Hoe)    -Has a long wooden/metal handle of variable length  -Has a metal blade which could be triangular or circular or rectangular in shape  -Metal blade is attached to one end of the handle b ns of a slim pointed metal projection     Specimen I (Short handle Sickíe)    -Has a curved metal blade  -The edge which is curved inside is sharp while the other edge is blunt  -Has a short wooden handle attached to one end of the curved metal blade.", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2010>2>b", "subject": "Agricultural Science Practical", "year": "2010", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "State two uses of each of specimens G, H, and I", "images": [], "marking_scheme": "Uses of Specimens G, H, and I;    Specimen G (CUTLASS) -    -For weeding   -For pruning   -Use for clearing the bush/slashing/brushing  -For cutting woods  -For planting  -For harvesting  -For transplanting  -Digging holes    Specimen H (HOE):    -Used for making ridges or heaps/seedbeds/mounds  -For weeding  -Planting or sowing seeds  -For harvesting  -Digging holes  -For loosening/turning the soil    Specimen I (SHORT HANDLE SICKLE);    -Used for harvesting cereals such as rice  -Used for cutting forage grasses for livestock.  -For weeding", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2010>2>c", "subject": "Agricultural Science Practical", "year": "2010", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : MAINTENANCE PRACTICES AND PRECAUTIONARY MEASURES", "question": "State three ways of maintaining the specimens in (a) and (b)", "images": [], "marking_scheme": "Ways of maintaining the specimens    -Sharpen the metal blades  -Wash and dry/clean after use  -Rub the metal blade with oil/grease to prevent rusting  -Keep the tools in a termite-free store to prevent the Wooden handles from damage  -Store in a cool, dry place after use  -Repair/replace damaged parts  -Straighten blades if bent", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2010>3>a", "subject": "Agricultural Science Practical", "year": "2010", "type": "Practical", "sub_label": "a", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "State one method of propagating each of specimens J (YAM TUBER), K (PLANTAIN), and L (TOMATO FRUIT) on the farm", "images": [], "marking_scheme": "Method of propagating specimens J, K and Specimen J    Specimen J(Yam tuber ): By seeds setts/mini setts/ whole yam tuber  Specimen K (Plantain): By Suckers, Corms  Specimen J (Tomato Fruit): By seeds", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2010>3>b", "subject": "Agricultural Science Practical", "year": "2010", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "Describe briefly the method of planting each of specimens J, K, and L.", "images": [], "marking_scheme": "Method of planting specimens J, K and L    Specimen J (Yam)    -Yam tubers are cut into setts  -Yam setts/seed yams are treated with an insecticide Or wood ash before planting/allow cut surface to dry under shade  -Make hole on the ridge/mound in the ground  -Place a yam sett or seed yam into the planting hole at a slanting angle with cut end up  -Yam setts/seed yams are planted at a spacing of 1m x 1m  -Cover the hole with soil  -Mulch with dry grass  -Provide stakes    Specimen K (Plantain)    -Dig holes about 60cm x 60cm x 60cm  -Fill the holes with a mixture of top soil and organic manure  -Place a sucker in each hole  -Cover the root part with soil  -The suckers are planted at a spacing of 4m x 4m  -Mulch planted suckers at the bases    Specimen L (Tomato)    -Sow seeds in nursery beds or boxes - under shade  Water regularly  -Transplant seedlings into the field after 4 -6 weeks or when the seedlings are at three-leaf stage  -Seedlings are planted at a spacing of 60cm x 60cm or 90cm x 40cm  -Transplant seedlings usually in the mornings or evenings  -Water seedlings daily  -Mulch seedlings  -Provide stakes", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2010>4>a", "subject": "Agricultural Science Practical", "year": "2010", "type": "Practical", "sub_label": "a", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "Name specimens N, O and P.", "images": [], "marking_scheme": "Names of Specimens N, O and P    N - Fish Scales  O - Feathers  P - Hoof", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2010>4>b", "subject": "Agricultural Science Practical", "year": "2010", "type": "Practical", "sub_label": "b", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "List two products that can be made from specimens M", "images": [], "marking_scheme": "Products that can be made from specimen M (Milk);    -Cheese  -Skim milk  -Butter/butter fat  -lce cream  -Powdered milk  -Yoghurt   -Milk candy/milk sweet/butter scotch", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2010>4>c", "subject": "Agricultural Science Practical", "year": "2010", "type": "Practical", "sub_label": "c", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "Make a drawing 8-10 cm long of a longitudinal section of specimens Q as observed with the aid of specimen S. Label the diagram fully.", "images": ["Agricultural Science Practical/imgs/2010/HPGHF6.jpg"], "marking_scheme": "", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2010>4>d", "subject": "Agricultural Science Practical", "year": "2010", "type": "Practical", "sub_label": "d", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "Štate two economic uses of each of specimens O and P.", "images": [], "marking_scheme": "Economic uses of Specimens O and P and sr Specimen O (Feathers) ;    -Decorating room/hats  -Stuffing into pillows / mattresses  -Source of income  -Part of traditional regalia  -For fertilizers and mulch  -Used for making feather meal for livestock feeding  -For sporting goods, e.g shuttlecock used in badminton  -Artificial lures for fishing/bait     Specimen P (Hoof);    -For gum making/glue making  -For making room decoration  -Making buttons  -Source of income", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2011>1>a", "subject": "Agricultural Science Practical", "year": "2011", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE", "question": "State the major elements contained in each of specimens A, B and C.", "images": [], "marking_scheme": "Maior element contained in specimens A, B, C    Specimen A -  Potassium  Specimen B - Carbon  Specimen C - Calcium", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2011>1>b", "subject": "Agricultural Science Practical", "year": "2011", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE", "question": "Give three uses of specimens A and B.", "images": [], "marking_scheme": "Uses of specimens A and B      Specimen A;    -It can be used as fertilizer  -It is a component of some fertilizer types  -Used in correcting soil acidity  -Used in controlling pests  -Important in the manufacture of soap  -Its leachates are Used in dye making  -Used as Scouring powder  -Sometimes added to compost manure when preparing it.    Specimen B;    -May be used in driving heat engines  -A source of heat for roasting/drying farm produce  -For warming brooder and piglet houses  -For boiling of water for processing of produce e.g palm oil production  -For purification of some compounds e.g. sugar  -Used as a toxin-binder/remover in feeds  -For goldsmithing and blacksmithing  -Soil sterilization when used to provide steam", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2011>1>c", "subject": "Agricultural Science Practical", "year": "2011", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE", "question": "Explain three ways in which specimen C is important in agriculture.", "images": [], "marking_scheme": "Ways in which specimen C is important in agriculture    Used .in decreasing soil acidity:  Used in decreasing fishpond water acidity  Increases availability of soil nutrients when added  It is a component of animal feed  For controlling leeches in fish ponds:  For controlling liver fluke by preventing hatching of water snail  Reduces turbidity in fish ponds  Increases activitíes of soil organism  Improves soil structure.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2011>1>d", "subject": "Agricultural Science Practical", "year": "2011", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE", "question": "Describe three physical differences between specimens B and C.", "images": [], "marking_scheme": "Description of physical differences between Specimen B and C;    Specimen B is black in colour while specimen C is creamy/white! light grey in colour  Specimen C has distinct crystals and layers while specimen B does not have.  Specimen B is amorphous while specimen C is crystalline  Specimen C is harder than specimen B  Specimen C is heavier than Specimen B", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2011>2>a>i", "subject": "Agricultural Science Practical", "year": "2011", "type": "Practical", "sub_label": "i", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING", "question": "Mention the field operation that could be performed Using specimens G, H, I and J", "images": [], "marking_scheme": "Field operation that could be performed using specimens G, H, I and J; Farm surveying", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2011>2>a>ii", "subject": "Agricultural Science Practical", "year": "2011", "type": "Practical", "sub_label": "ii", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING", "question": "Name three other pieces of equipment that may be added to specimens G, H, l, and J to perform the operation you have mentioned in (a)(i).", "images": [], "marking_scheme": "Other equipment that may be added to specimens GH, l and J to perform the operation, mentioned in (a)(i)    -Levelling staff  -Abney level.  -Dumpy level  -Theodolite.  -Prismatic compass  -Gunter's chain/ metric chain/engineer's chain  -Offset staff/pin", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2011>2>a>iii", "subject": "Agricultural Science Practical", "year": "2011", "type": "Practical", "sub_label": "iii", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING", "question": "State one precaution that should be taken when using specimen J.", "images": [], "marking_scheme": "Precaution that should be taken when using specimen J (Garden line)    -Do not drag /rub against rough surfaces/edges  -Do not pull too hard when taking measurements to avoid damage/snapping  -Properly tie to the pole to avoid accidental release when in use and to ensure accurate readings  -Must be straight and horizontal for accurate measurements", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2011>2>b>i", "subject": "Agricultural Science Practical", "year": "2011", "type": "Practical", "sub_label": "i", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "State two uses of each specimen K and L.  Specimen K;        Specimen L;", "images": [], "marking_scheme": "Uses of specimens K and L.    Uses of specimen K(Hand trowel)   -Transplanting of seedlings  -Planting of seeds  -Application of fertilizers/manure  -Loosening of soils  -Mixing of fertilizers  -For light weeding    Uses of specimen L (Mattock) -    -Digging of soil  -Uprooting stumps from farmlands  -Removal of stones  -Clearing of bush  -Land preparation  -Breaking hard pans on farmlands", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2011>2>b>ii", "subject": "Agricultural Science Practical", "year": "2011", "type": "Practical", "sub_label": "ii", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "State two structural differences between specimens K and L.", "images": [], "marking_scheme": "Structural differences between specimen K and L    -Specimen K (Hand trowel) has a boat-shaped blade whereas, Specimen L (Máttock) has a thick block of iron blade  -Specimen K (Hand trowel) has a short wooden cylindrical handle whereas; specimen L(Mattock) has a long cylindrical wooden handle  -Specimen K (Hand trowel) total length is about 30cm whereas; specimen L total length is about 100cm.  -Specimen K( Hand trowel) blade is pointed only at one end whereas, specimen L (Mattock) one end of the blade is long, blocky and. pointed, and the other broad, flat and sharp at the other end which is also metallic.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2011>2>b>iii", "subject": "Agricultural Science Practical", "year": "2011", "type": "Practical", "sub_label": "iii", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "Mention two problems that could result from leaving specimen L on the field after use.", "images": [], "marking_scheme": "Problems that could result from leaving specimen L(Mattock) on the field after use    -Wooden handle may be attacked by termites  -Metal blade will rust on contact with water  -Farm machinery may run over and damage it or may be damaged  -It may injure farm workers  -Could be stolen", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2011>3>a", "subject": "Agricultural Science Practical", "year": "2011", "type": "Practical", "sub_label": "a", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "Identify specimens M, N, and O by their common names and their scientific names.", "images": [], "marking_scheme": "ldentification of specimens M, N and O by their Common name and their scientific names.  SpecimenCommon NameScientific NameMCoconutCocos nuciferaNSweet PepperCapsicum annumOSweet OrangeCitrus spp.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2011>3>b>i", "subject": "Agricultural Science Practical", "year": "2011", "type": "Practical", "sub_label": "i", "group": "", "topic": "CROP PROTECTION : DISEASES OF CROPS~~CROP PROTECTION : PESTS OF CROPS", "question": "Name one pest and one disease that attack the crop from which specimen O is obtained.", "images": [], "marking_scheme": "Pests and Diseases that attack the crop from which specimen O (Sweet Orange) is obtained    Pests;    Aphids  Scale insets  Caterpillars of the swallow-tailed butterfly  Citrus nematodes  Red mites  Thrips  Fruit borers  Termites  Mammalian pests, e.g monkeys, apes    Diseases -    Gummosis /Collar disease  Tristeza  Citrus scab  Die backs  Citrus nematodes disease", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2011>3>b>ii", "subject": "Agricultural Science Practical", "year": "2011", "type": "Practical", "sub_label": "ii", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "State one control measure for each of the pests and diseases mentioned in (b)(i)", "images": [], "marking_scheme": "Control measures for pests and diseases of specimen O    Pests -    Use of insecticides  Hand picking  Use of appropriate nematicide  Use of disease-resistant varieties  Soil sterilization  Setting of traps/shooting   Diseases;    Gummosis;    Growing of resistant varieties as stock  Maintain good farm sanitation  Well-drained soil  Apply coal tar around affected portion  Application of fungicide  Citrus Scab;    Treat with appropriate copper-based fungicides e.g. Bordeaux mixture  Plant scab-resistant varieties  Die - backs;    Fumigate soil with aidrin dust carbon disuiphide  Treat with furadan or carbamade  Tristeza;    Use resistant rootstocks e.g.rough lemon or Cleopatra orange", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2011>3>c", "subject": "Agricultural Science Practical", "year": "2011", "type": "Practical", "sub_label": "c", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "Mention three uses of specimen M.", "images": [], "marking_scheme": "Uses of specimen M (Coconut) -    For food/refreshment.  Copra used in livestock feed.  Production of vegetable oil  Used in the manufacture of fibre for brushes and foot mats  Source of fuel Herbal medicine  Crafts/decoration  Shell used as abrasive  Coconut water is used in producing fruit juice/beverages (alcoholic non alcoholic)  Oil used for producing creams", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2011>3>d", "subject": "Agricultural Science Practical", "year": "2011", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ECONOMICS AND EXTENSION : MARKETING OF AGRICULTURAL PRODUCE", "question": "State two methods of preserving specimen N", "images": [], "marking_scheme": "Methods of preserving specimen N (Sweet pepper)    Refrigeration  Prickling  Freeze-drying  Sun-drying/drying  Canning", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2011>4>a", "subject": "Agricultural Science Practical", "year": "2011", "type": "Practical", "sub_label": "a", "group": "", "topic": "PARASITES", "question": "ldentify specimen P, Q, and R.", "images": [], "marking_scheme": "ldentification of specimen P, Q and R    P - Tapeworm  Q - Liverfluke  R - Tick", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2011>4>b", "subject": "Agricultural Science Practical", "year": "2011", "type": "Practical", "sub_label": "b", "group": "", "topic": "PARASITES", "question": "Name the part of the host where each of specimens P, Q and R can be found.", "images": [], "marking_scheme": "Name of the part of the host where, specimens P,Q and R can be found    P - Intestine of host'  Q - Inside the liver/bile duct  R - Skin/body of host", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2011>4>c", "subject": "Agricultural Science Practical", "year": "2011", "type": "Practical", "sub_label": "c", "group": "", "topic": "PARASITES", "question": "Mention three ways by which specimen P is adapted to survive in the host.", "images": [], "marking_scheme": "Ways by which specimen P is adapted to survive in the host    Head/scolex has suckers and hooks for firm attachment to host.  Head/scolex for sucking the nutrients and blood from host.  Has many segments/proglottids which have complete reproductive structures. These increase their survival  They have both male and female reproductive structures, which favours self-fertilization  They secrete chemicals that ensure their freedom from the digestive enzymes of the host  Nutrients are absorbed by all surfaces of the body/ large surface area  Formation of cysts around the bladder worm, ensuring the survival of the bladder worm in the reproductive cycle.  The proglottids contain several eggs which increase the possibility of survival; even if several perish, many will still survive.  Body covered with tough cuticle which resists digestion by the host", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2011>4>d", "subject": "Agricultural Science Practical", "year": "2011", "type": "Practical", "sub_label": "d", "group": "", "topic": "PARASITES", "question": "State three effects of specimen Q on the host", "images": [], "marking_scheme": "Effects of Specimen Q (Tapeworm) on the host    Obstructs flow of bile into the intestines    Destroys liver tissue thus causing liver rot   Reduces digestion of fat in' the host  Causes mal absorption of nutrients  Causes emaciation and death of host in large numbers  Weakness of the host", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2011>4>e", "subject": "Agricultural Science Practical", "year": "2011", "type": "Practical", "sub_label": "e", "group": "", "topic": "PARASITES", "question": "List four diseases transmitted by specimen R.", "images": [], "marking_scheme": "Diseases transmitted by Specimen R (Tick)    Heart water disease  Red water disease/Babesiosis  Tick fever  Tick paralysis  Mange  Scabies", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2011>4>f", "subject": "Agricultural Science Practical", "year": "2011", "type": "Practical", "sub_label": "f", "group": "", "topic": "PARASITES", "question": "State four control measures of specimen R.", "images": [], "marking_scheme": "Control measures for Specimen    Dipping in acaricide solution.  Spraying with acaricides.  Hand - picking.  Rotational Grazing / Paddocking  Regular cleaning of pens.  Changing of beddings regularly  Controlled burning of pastures", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2012>1>a>i", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "i", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "Give two examples of each of specimens A and B.", "images": [], "marking_scheme": "Specimen A (Organic fertilizer):    Green manure.  Compost.  Guano.  Farmyard manure/cattle/sheep/goat/rabbit/pig/fish, etc.  Specimen B(Inorganic fertilizer:    Urea  Sulphate of Ammonia  NPK  Muriate of Potash  Lime  Single superphosphate  Triple superphosphate  Calcium ammonium nitrate  Diammonium phosphate  Potassium nitrate", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2012>1>a>ii", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "ii", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "State three advantages of the application of specimen A in crop production", "images": [], "marking_scheme": "Advantages of the application of specimen A (Organic fertilizer) in crop production    Improves soil structure   Increases activities of soil microbes  Increases water holding capacity  Increases Cation Exchange Capacity (CEC)  Reduces soil erosion  Improves buffering capacity of the soil  Nutrients not easily leached  Improves soil aeration  It stabilizes soil temperature  It stays longer in soil", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2012>1>a>iii", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "iii", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "Mention two methods of applying specimen B in crop production.", "images": [], "marking_scheme": "Methods of applying Specimen B (Inorganic fertilizer)    Broadcasting  Band placement  Ring method  Side dressing/Row placement  Foliar application  Fertigation/Application through irrigation method  Plough-sole method  Top dressing", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2012>1>b>i", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "i", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT", "question": "An experiment was conducted to determine the percentage of water in soil samples C and D.  The results are as shown in the table below:  Soil SampleSoil SampleData RecordedCDMass of crucible80g80gMass of crucible and fresh soil100g140gMass of crucible and soil after heating95g100g    Determine the mass of fresh soil for each of soil samples C and D", "images": [], "marking_scheme": "Determination of mass of fresh soil samples C and D    Soil Sample C;    Mass of crucible and fresh soil - Mass of crucible = 100g - 80g = 20g    Soil Sample D;    Mass of crucible and fresh soil - Mass of crucible = 140g - 80g = 60g", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2012>1>b>ii", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "ii", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT", "question": "An experiment was conducted to determine the percentage of water in soil samples C and D.  The results are as shown in the table below:  Soil SampleSoil SampleData RecordedCDMass of crucible80g80gMass of crucible and fresh soil100g140gMass of crucible and soil after heating95g100g  Determine the mass of water contained in each of soil samples C and D", "images": [], "marking_scheme": "Determination of mass of water contained in soil samples C and D    Soil Sample C; Mass of crucible and fresh soil - Mass of crucible and soil after heating = 100g - 95g = 5g    Soil Sample D; Mass of crucible and fresh soil - Mass of crucible and soil after heating = 140g - 100g = 40g", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2012>1>b>iii", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "iii", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT", "question": "An experiment was conducted to determine the percentage of water in soil samples C and D.  The results are as shown in the table below:  Soil SampleSoil SampleData RecordedCDMass of crucible80g80gMass of crucible and fresh soil100g140gMass of crucible and soil after heating95g100g  Calculate the percentage of water in each of soil samples C and D.", "images": [], "marking_scheme": "Calculation of percentage of water in each soil sample (i.e.C and D)     Mass crucible and fresh soil - Mass of crucible  = yg  Mass of crucible and soil after heating - Mass of crucible = zg  yg = mass of fresh soil   zg = mass of soil after heating   % water = y-z/y  For soil sample C  100g - 80g = 20g  → y  95g - 80g = 15g  →  z  20g-15g x 100/20g = 25%    For soil sample D  140g - 80g = 60g  → y  100g - 80g = 20g  →  z  60g-20g x 100/60g = 66.66%", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2012>1>c", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ECOLOGY : ENVIRONMENTAL FACTORS AFFECTING CROP AND ANIMAL DISTRIBUTION AND PRODUCTION", "question": "What type of relationship exists between the amount of water and the amount of air in soils?", "images": [], "marking_scheme": "Relationship that exists between the amount of water and the amount of air in soils: The amount of air in the soil is inversely proportional to the amount of water in the soil pore spaces which are not occupied by water.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2012>2>a", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "identify specimens H, I, J, K, L and M", "images": [], "marking_scheme": "identification of specimens H, I, J, K, L and M    Specimens H - Cutlass  I - Hoe  J - Shears  K - Rake  L - Watering can  M - Shovel", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2012>2>b", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS~~AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "State one major use of each of specimens H, I, J, K, L and M", "images": [], "marking_scheme": "Major use of each of specimens H, I, J, K, Land M    Specimen H-(Cutlass):    For clearing and slashing bushes  For weeding  For light digging like transplanting  Planting/sowing  Harvesting crops like coconut, banana, etc  For digging holes for the fixing of fence poles  Specimen I -(Hoe):    Making ridges and seedbeds for crops and vegetables  Weeding of plants  Harvesting of crops like groundnuts, cassava, yams  Planting/sowing  Mixing of fertilizer with the soil  Specimen J-(Shears):    Trimming of hedges  For removing dead parts or excessive branches/pruning  Specimen K- (Rake):    Removing rubbish from the farm  Covering vegetable seeds when broadcast  Removing stones from seedbeds  Leveling of soil surface  Spreading of manure  Specimen L-(Watering Can):    Supplying water to young seedlings in the seedbeds and nursery  Irrigation of flowers  Sprinkling of foliar fertilizers  Specimen M-(Shovel):    Transferring soil from one place to another  Harvesting of root-tuber crops  Light weeding in the farm  Excavation or digging of the soil", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2012>2>c", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "State three general maintenance practices for specimens H, J, and M", "images": [], "marking_scheme": "General maintenance practices for specimen H (cultlass) J (Shears) and M (shovel)    Clean after use  Wash and dry after use  Lubricate/oil metal part/joints before storing  Sharpen/straighten metal blades  Tighten the loose joint Replace worn out part  Store in cool dry place  Keep wooden handle away from termite", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2012>2>d", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "Name one tractor-coupled implement that can perform similar functions as each of specimens H, I and K", "images": [], "marking_scheme": "Tractor-coupled implement that can perform similar functions as specimens H, l and K;    H - Lawn mower/slasher  I - Disc plough/Mouldboard plough/ridger  K - Harrow or any named cultivator", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2012>3>a", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "a", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "ldentify each of specimens N, O, P and Q.", "images": [], "marking_scheme": "ldentification of specimens N, O, P and Q Specimens    N Groundnut seeds  O Maize seeds/grains  P Guinea corn seeds/sorghum  Q- Aphids/aphid", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2012>3>b", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PRODUCTION : CLASSIFICATION OF CROPS", "question": "Determine the plant population per hectare, if one seed of specimens N is sown per hole at a spacing of 60cm x 25cm", "images": [], "marking_scheme": "Determination of plant population of specimen  Plant population stand = Area of farmland/Feeding area per plant x plant  = 1ha x1 plant/60cm x 25cm    OR    10,000m2 x 1 plant/0.15m2  =66,666.7/66,667 plants", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2012>3>c", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "c", "group": "", "topic": "CROP PRODUCTION : CROP IMPROVEMENT", "question": "State two reasons for the inclusion of the plant from which specimen N is obtained in crop rotation", "images": [], "marking_scheme": "Reasons for the inclusion of the plant from which specimen N is obtained in crop rotation    For nitrogen fixation  Controls erosion  Controls weeds by smothering them", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2012>3>d", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "d", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "Mention three uses of specimen P.", "images": [], "marking_scheme": "Uses of specimen P (Guinea corn seed)    Food for human  Feed for animal  Production of alcoholic drinks  Stalk for roofing/staking  Stalk/Leaves as a source of fuel  Propagation material", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2012>3>e", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "e", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "State two ways by which the activities of specimen Q affect crops", "images": [], "marking_scheme": "Ways by which the activities of specimen Q (Aphids) affect crops;    They pierce through the outer tissues of young leaves, stems, and pods, sucking the nutritional sap  Distortion of leaves  Defoliation and death of the plant  Transmission of viral diseases  Reduction in crop yield  Reduction of photosynthetic leaf area in crops", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2012>4>a>i", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "i", "group": "", "topic": "ANIMAL PRODUCTION : RANGELAND AND PASTURE MANAGEMENT", "question": "ldentify specimens R.", "images": [], "marking_scheme": "identification of Specimen R    Specimen R - Lantern/Hurricane lamp", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2012>4>a>ii", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "ii", "group": "", "topic": "ANIMAL PRODUCTION : RANGELAND AND PASTURE MANAGEMENT", "question": "State two disadvantages of using specimen R in poultry house.", "images": [], "marking_scheme": "Disadvantages of using specimen R (Lantern/ Hurricane Lamp) in poultry house    It pollutes the air due to the emission of carbon monoxide/soot.  Can lead to a fire outbreak if tripped over by birds.  Birds may be trapped between the space/handle and the tank of the lantern and this might lead to death.   High cost of fuel.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2012>4>a>iii", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "iii", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "State two precautions to be taken when using specimen R", "images": [], "marking_scheme": "Precautions to be taken when using specimen R(Lantern/Hurricane Lamp) in poultry house    Ensure that lantern is placed ín a raised position to avoid being tripped over by the birds.  Ensure that the fuel tank is securely locked.  Ensure that a little quantity of kerosene/fuel is put inside the tank at any time.  Provide a protective guard around the lantern to avoid birds perching on it/coming into contact with  it Regulates the light to reduce the emission of carbon monoxide/soot.  Ensure there is no leakage of kerosene", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2012>4>a>iv", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "iv", "group": "", "topic": "AGRICULTURAL ECONOMICS AND EXTENSION : FARM MANAGER", "question": "List two ways of maintaining specimen R", "images": [], "marking_scheme": "Ways of maintaining specimen R (Lantern/ Hurricane Lamp)    Clean the glass/shade regularly,  Remove deposit of soot at the upper end of the chimney.  Wash the fuel chamber/tank to get rid of sediments.  Wash and dry the wick when it is too dirty for good heat generation.  Replace old wick regularly.  Clean the metal part of any form of feaces to avoid rusting.  Do not allow the lantern to be placed in a wet or damp environment to prevent rusting.", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2012>4>a>v", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "v", "group": "", "topic": "ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT", "question": "Name two devices that can be used in place of using specimen R in a poultry house.", "images": [], "marking_scheme": "Devices that can be used in place of specimen damp environment to prevent rusting. R (Lantern/Hurricane Lamp) in poultry house    Electric bulbs  Stoves  Heaters", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2012>4>b>i", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "i", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL REPRODUCTION", "question": "A farmer observed that ten of the sows on the pig farm had reddened and swollen vulvas with whitish mucus discharge. The sows also made undue noise and P mounted one another. Use the information to answer the questions that follow:    What do the observed signs in the sows indicate?", "images": [], "marking_scheme": "Observed signs in the sows indicated: Heat / oestrus", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2012>4>b>ii", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "ii", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL REPRODUCTION", "question": "A farmer observed that ten of the sows on the pig farm had reddened and swollen vulvas with whitish mucus discharge. The sows also made undue noise and P mounted one another. Use the information to answer the questions that follow:  Assuming the farmer serviced a sow on 1st March, 2012, state the date the farmer should expect the sow to farrow.", "images": [], "marking_scheme": "The farmer should expect the sows to farrow on:  25th June 2012 (+/-2 days)", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2012>4>b>iii", "subject": "Agricultural Science Practical", "year": "2012", "type": "Practical", "sub_label": "iii", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL REPRODUCTION", "question": "A farmer observed that ten of the sows on the pig farm had reddened and swollen vulvas with whitish mucus discharge. The sows also made undue noise and P mounted one another. Use the information to answer the questions that follow:  List three preparations that the farmer should make in the farrowing pen before the sow farrows.", "images": [], "marking_scheme": "Preparations to make in the farrowing pen before the sows farrow:    Clean the farrowing pen.  Keep the environment dry.  Disinfect pen about 6 - 7 days before farrowing.  Provide good and clean litter.  Provide enough space to accommodate the farrowing process.  Provide farrowing crates if available  Provide creep feed.  Fencing for biosecurity.  Allow her to get accustomed to her new  Provision of adequate feed to prevent cannibalism (the sow from eating the litters) surroundings and settle down", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2013>1>a", "subject": "Agricultural Science Practical", "year": "2013", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ECOLOGY : ROCK FORMATION", "question": "Identify specimens D, E and F", "images": [], "marking_scheme": "dentification of specimens D, E, and F    Specimens D; Pebbles or sanstone  Specimen E ; Granite  Specimen F: Marble", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2013>1>b", "subject": "Agricultural Science Practical", "year": "2013", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ECOLOGY : ROCK FORMATION", "question": "Classify specimens D, E and F according to their mode of formation", "images": [], "marking_scheme": "Classification of specimens D, E and F acorrding to the mode of formation    D- Sedimentary rock    E- lgneous rock    F-Metamorphic rock", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2013>1>c", "subject": "Agricultural Science Practical", "year": "2013", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ECOLOGY : ROCK FORMATION", "question": "State three characteristics of each of specimens D and E", "images": [], "marking_scheme": "Characteristics of specimens D and E    Specimen D (Pebbles/ Sandstone)    Occurs in layers or strata  May be coarse, fine, soft or hard  Non-crystalline in nature  May contain fossils/plant and animal remains  Not resistant to erosion  May be porous  Specimen E (Granite)    Crystalline in nature/contain crystals   Very hard  It is massive  Impermeable to water  Highly resistant to erosion and weather element  Does not contain fossils", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2013>1>d", "subject": "Agricultural Science Practical", "year": "2013", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ECOLOGY : ROCK FORMATION", "question": "State three ways in which specimen E is economically important.", "images": [], "marking_scheme": "Ways in which specimen E (Granite) is economically important    Sources of minerals  Used as grinding stone  For sharpening of cutlasses and knives  As bunds to prevent erosion  To crack hard kernels/seeds  For road construction in farms  For building houses  Can be polished and used for decorations  Source of foreign exchange  Source of job opportunity", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2013>2>a", "subject": "Agricultural Science Practical", "year": "2013", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "ldentify specimens I, J and K", "images": [], "marking_scheme": "Identification of specimens I, J and K    Specimen I; Shears  Specimen J; Secateurs  Specimen K; Spade", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2013>2>b", "subject": "Agricultural Science Practical", "year": "2013", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "State two uses of each of specimens I and J", "images": [], "marking_scheme": "Specimen J(secateurs) -    Preparing cuttings  Harvesting some beverage plant  Prunning  Cutting flowers and ornamental plant", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2013>2>c", "subject": "Agricultural Science Practical", "year": "2013", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "Give two maintenance practices for each of specimens I and K", "images": [], "marking_scheme": "Maintenance practices of specimen    Specimen I(Shears)    Sharpen the blade  Straighten blade when bending  Lubricate fulcrum  Oil blade  Tightening of bolt  Apply termite repellent treatment  Store in Cool, dry place  Clean after use/wash after use  Specimen K(Spade)    Straighten bent blade  Replace damaged handles  Replace damaged handle  Sharpen the cutting edge  Apply termite repellant  Apply grease/oil to the blade  Store in cool, dry place  Clean after use/wash and dry", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2013>2>d", "subject": "Agricultural Science Practical", "year": "2013", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "Describe specimen K", "images": [], "marking_scheme": "Description of specimen K;    Has a long wooden handle  Has a rectangular, flat, metal blade with one sharpened end  One end of the handle is fixed to the metal blade   The other end is shaped to facilitate handling the tool during use", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2013>2>e", "subject": "Agricultural Science Practical", "year": "2013", "type": "Practical", "sub_label": "e", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "Name two other farm tools that can perfom the functions of specimen K", "images": [], "marking_scheme": "Other farm tools that can perform the functions of specimen K(Spade)    Shovel  Hoe", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2013>3>a", "subject": "Agricultural Science Practical", "year": "2013", "type": "Practical", "sub_label": "a", "group": "", "topic": "CROP PRODUCTION : PASTURE AND FORAGE CROPS", "question": "ldentify specimens N,O and P by their common and botanical names", "images": [], "marking_scheme": "SpecimenCommon NameBotanical NameNElephant grassPennisetun purpureumOCentro/CentrosemaCentrosema pubescensPTropical KudzuPueraria phaseoloides", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2013>3>b", "subject": "Agricultural Science Practical", "year": "2013", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PRODUCTION : PASTURE AND FORAGE CROPS", "question": "State how each of specimens N and O is propagated", "images": [], "marking_scheme": "SpecimenMethod PropagationNStolonsOSeeds", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2013>3>c", "subject": "Agricultural Science Practical", "year": "2013", "type": "Practical", "sub_label": "c", "group": "", "topic": "CROP PRODUCTION : PASTURE AND FORAGE CROPS", "question": "Give four characteristics of specimen O", "images": [], "marking_scheme": "Characteristics of specimen O (Centro) -    Vigorous and aggressive growing legume  Creeping and twining plant  Has trifoliate leaves attached to the stem by pulvinus  Leafy, perennial, and shade tolerant  Drought resistant  Highly nodulated/contains bacteria in the nodules  Highly palatable and very nutritious", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2013>3>d", "subject": "Agricultural Science Practical", "year": "2013", "type": "Practical", "sub_label": "d", "group": "", "topic": "CROP PRODUCTION : PASTURE AND FORAGE CROPS", "question": "State three uses of specimen N", "images": [], "marking_scheme": "Uses of specimen N (Elephant grass)    For feeding livestock  For roofing/thatching of roof  As mulch material to conserve soil moisture  As bedding materials in livestock houses/pens  Planted to prevent soil erosion  Stalk is used as fuel  Dried stems can be used for fencing  Used for paper pulp production  For compost making", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2013>4>a", "subject": "Agricultural Science Practical", "year": "2013", "type": "Practical", "sub_label": "a", "group": "", "topic": "ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT", "question": "ldentify specimens Q, R and S", "images": [], "marking_scheme": "Q- Pieces of meatbeef/mutton/pork/goat meat/poultry meat  R-Leather   S-Feather", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2013>4>b", "subject": "Agricultural Science Practical", "year": "2013", "type": "Practical", "sub_label": "b", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "Mention three types of livestock from which both specimens Q and R can be obtained", "images": [], "marking_scheme": "Types of livestock from which both specimens Q and R can be obtained    Cattle  Sheep   Goats  Horses  Camel", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2013>4>c>i", "subject": "Agricultural Science Practical", "year": "2013", "type": "Practical", "sub_label": "i", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "State three nutritional values of specimen Q", "images": [], "marking_scheme": "Nutritional values of specimen Q(Pieces of meat)    Supplies proteins to the body  Supplies vitamins to the body  Supplies oil and fat to the body  Supplies energy to the body", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2013>4>c>ii", "subject": "Agricultural Science Practical", "year": "2013", "type": "Practical", "sub_label": "ii", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "Mention four uses of specimen R", "images": [], "marking_scheme": "Uses of specimen R(Leather    For making shoes   For making belts  For decorative purposes   For making hand gloves  Used as mat  Used as clothing materials  For upholstery works/to cover furniture  For making drums  For making bags  For making amulet/leather band", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2013>4>d", "subject": "Agricultural Science Practical", "year": "2013", "type": "Practical", "sub_label": "d", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "State two ways by which specimen S is important to poultry", "images": [], "marking_scheme": "Ways in which specimen S(Feather) is important to poultry    Serves for body protection  Helps in flight  Keeps the bird's body warm/insulation  Production/generation of heat during natural brooding  Gives shape and beauty to the bird", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2014>1>a>i", "subject": "Agricultural Science Practical", "year": "2014", "type": "Practical", "sub_label": "i", "group": "", "topic": "AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "identify specimens A(Clayey soil) and  B(Sandy soil) by the feel method.", "images": [], "marking_scheme": "Identification of Specimens A and B by the feel method:    Specimens: A- Clayey Soill Clay.  B-Sandy Soil/Sand.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2014>1>a>ii", "subject": "Agricultural Science Practical", "year": "2014", "type": "Practical", "sub_label": "ii", "group": "", "topic": "CROP PRODUCTION : CLASSIFICATION OF CROPS", "question": "Name two crops that would thrive well on each of specimens A and B", "images": [], "marking_scheme": "Crops that would thrive well on each of Specimens A and B:    Specimen A (Clayey soil): - Rice- Mango - Citrus - Rubber - Sugar cane - Cocoa -Oil palm -Potatoes -Cabbage.  Specimen B (Sandy soil): Pineapple- Cashew - Kenaf- Jule- Pigeon -Cowpea - Coconut -Guinea corn-mEggplant -Cassava", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2014>1>a>iii", "subject": "Agricultural Science Practical", "year": "2014", "type": "Practical", "sub_label": "iii", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "Mention three ways by which specimen B can be improved", "images": [], "marking_scheme": "Ways by which Specimen B(Sandy soil) can be improved:    Application of Io compost/farmyard manure.  Mulching  Planting of cover crops/cover cropping  Liming  Application of inorganic fertilizer  Bush fallowing  Irrigation  Addition of clay", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2014>1>b>i", "subject": "Agricultural Science Practical", "year": "2014", "type": "Practical", "sub_label": "i", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "identify specimens C and D", "images": [], "marking_scheme": "identification of Specimens C and D    Specimens C- Millipede  D -Cow dung", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2014>1>b>ii", "subject": "Agricultural Science Practical", "year": "2014", "type": "Practical", "sub_label": "ii", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "State three ways in which specimen C is important in crop production.", "images": [], "marking_scheme": "Ways in which Specimen C (Millipede) is important in crop production    Helps to improve soil structure.  Helps in the breakdown of organic matter.  Improves/enhance soil aeration.  Adds organic matter/nutrients to the soil through defecation and decay.  Enhances cation exchange capacity of the soil.   Improves water percolation.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2014>1>b>iii", "subject": "Agricultural Science Practical", "year": "2014", "type": "Practical", "sub_label": "iii", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "State three uses of specimen D in agriculture.", "images": [], "marking_scheme": "Uses of Specimens D (Cow dung) in agriculture.     To improve sandy soil/ improve soil structure/holding soil particles together.  Added to the soil to supply plant nutrients/improves soil fertility.  For making compost/farmyard manure.  Used to generate biogas/fuel.  To fertilize fish ponds.  Ingredient for making mud bricks.  For coating the floor in mud houses/structures on the farm.  Burnt to repel mosquitoes on the farm.  Improves water holding capacity of soils.  Enhances the activities of soil microorganisms.", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2014>2>a>i", "subject": "Agricultural Science Practical", "year": "2014", "type": "Practical", "sub_label": "i", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS~~AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "identify specimen H, I, J and K", "images": [], "marking_scheme": "identification of Specimens H, I, J and K: Specimens: H- Shears I-Sickle J- Knapsack sprayer K-Wheelbarrow", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2014>2>a>ii", "subject": "Agricultural Science Practical", "year": "2014", "type": "Practical", "sub_label": "ii", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "State two uses of each of specimens J and k", "images": [], "marking_scheme": "Uses of Specimens J and K    Specimen J (Knapsack sprayer):    Used for spraying insecticides/fungicides/pesticides.  Used for spraying herbicides.  Used for light irrigation/watering of vegetable beds.  Used for spraying liquid fertilizers/foliar application of liquid fertilizer.  Used for spraying disinfectants on livestock houses and structure.  Specimen K (Wheel barrow): -    Used for carrying farm inputs,  Used for carrying farm outputs/products.  Used to dispose farm debrics and waste.  Used for carrying materials for building farm structures.", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2014>2>a>iii", "subject": "Agricultural Science Practical", "year": "2014", "type": "Practical", "sub_label": "iii", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "State three general ways of maintaining specimens H and I", "images": [], "marking_scheme": "General ways of maintaining Specimens H (Shears) and I(Sickle):    Wash and dry after use clean after use.  Store in a cool, dry place.  Sharpen blades regularly.  Grease/lubricate metal blades before storage.  Keep wooden handles away from termites.  Replace worn-out parts.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2014>2>a>iv", "subject": "Agricultural Science Practical", "year": "2014", "type": "Practical", "sub_label": "iv", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "State four precautions to be taken when using specimen J", "images": [], "marking_scheme": "Precautions to be taken when using Specimen J.    Use protective clothing when spraying.  Do not smoke., eat or drink when spraying.  Do not use it when it is windy.  Do not spray against the wind direction.  After use, always wash hands and face before attempting to eat, drink or smoke.  Never blow to clear the blocked nozzle with the mouth.  Clean or wash all protective clothing after use.  Dispose of all empty Containers safely into dug pits.  Wear a nose mask  Do not point the spray in the direction sprayer of persons, animal,s or food items.  Use separate sprayer for different chemicals to avoid mask contamination.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2014>3>a>i", "subject": "Agricultural Science Practical", "year": "2014", "type": "Practical", "sub_label": "i", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "Forth maize seeds were sown on a raised bed and thirty-five seeds germinated.  Calculate the percentage of the maize seeds that germinated", "images": [], "marking_scheme": "Percentage of the maize seeds that germinated = No of germinated seeds/no of seeds sown x 100/1  Percentage of the maize seeds that germinated = 35/40 x 100/1 = 87.5%", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2014>3>a>ii", "subject": "Agricultural Science Practical", "year": "2014", "type": "Practical", "sub_label": "ii", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "What is the percentage of the maize seeds that did not germinate?", "images": [], "marking_scheme": "Percentage of the maize seeds that did not germinate = No of ungerminated seeds/no of seeds sown x 100/1  Percentage of the maize seeds that did not germinate = 5/40 x 100/1 = 12.5%    OR    Percentage of the maize seeds that did not germinate = 100% of seeds that germinate                      100 - 87.5% = 12.5%", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2014>3>b", "subject": "Agricultural Science Practical", "year": "2014", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "State four conditions that could have enhanced the germination of the thirty-five seeds", "images": [], "marking_scheme": "Conditions that enhanced the germination of the thirty-five seeds:    Suitable soil temperature  Air (oxygen)  Good soil  Adequate moisture/ water  Viable seeds/seed viability  Planting at the right depth", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2014>3>c", "subject": "Agricultural Science Practical", "year": "2014", "type": "Practical", "sub_label": "c", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "Suggest five reasons why some of the seeds did not germinate", "images": [], "marking_scheme": "Reasons why some of the seeds did not germinate:    Seeds might be too old/not viable  Seeds might be infested with disease organisms  Seeds might have been removed and eaten by birds or rodents/pests  Seeds might have been sown too deep  Seeds might have been damaged.  Inadequate moisture/ water.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2014>3>d", "subject": "Agricultural Science Practical", "year": "2014", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ECOLOGY : AGRO-ALLIED INDUSTRIES AND RELATIONSHIP BETWEEN AGRICULTURE AND INDUSTRY", "question": "Give two industrial uses of maize seeds.", "images": [], "marking_scheme": "Industrial uses of maize seeds:    Used in the production of pharmaceutical/drugs  Used in the production of biofuel Used in making adhesives  Used in the brewery  Used in making livestock feed  Used in making processed food for man e.g Baby food, corn flakes  Used in the production of corn oil  Used in the production of starch", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2014>4>a>i", "subject": "Agricultural Science Practical", "year": "2014", "type": "Practical", "sub_label": "i", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "identify specimens P and R", "images": [], "marking_scheme": "ldentification of Specimens P and R:    Specimens P- Saw dust  R- Bird", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2014>4>a>ii", "subject": "Agricultural Science Practical", "year": "2014", "type": "Practical", "sub_label": "ii", "group": "", "topic": "ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT", "question": "State three reasons why the use of specimen P is not recommended in a brooder house", "images": [], "marking_scheme": "Reasons why the use of specimen P (Saw dust) is not recommended in a brooder house:    It contaminates the feed  It contaminates the water  It may get into the eyes of the chicks and lead to blindness.  It may lead to breathing difficulty if  it enters the nostrils of chicks,  Chicks tend to feed on it and in the process may contact s disease.  Cakes up easily and loses the ability to h absorb droppings.  May accommodate sharp objects like nails which could harm the farmer animal.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2014>4>a>iii", "subject": "Agricultural Science Practical", "year": "2014", "type": "Practical", "sub_label": "iii", "group": "", "topic": "ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT", "question": "Mention two other materials that could be used in place of specimen P in a brooder house", "images": [], "marking_scheme": "Alternative material for Specimen P(Saw dust) in a brooder house:-    Rice Husk  Wood shavings  Ground maize cobs  Crushed dry Kenaf stems.  Dry grass.  Dried groundnut husks", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2014>4>a>iv", "subject": "Agricultural Science Practical", "year": "2014", "type": "Practical", "sub_label": "iv", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "What is the name given to the product formed when poultry droppings mix with specimen P?", "images": [], "marking_scheme": "Name given to the product formed when poultry dropping mix with Specimen P (Sawdust): - Farmyard manure/poultry manure.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2014>4>a>v", "subject": "Agricultural Science Practical", "year": "2014", "type": "Practical", "sub_label": "v", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "State four uses of the product mentioned in (a) (iv) in agricultural production", "images": [], "marking_scheme": "Uses of the product mentioned in a(iv) in agricultural production: -    To improve soil fertility.  To improve soil structure/binds soil particles together.  For compost making.  For fertilization of fish pond ruminants/part of the feed for ruminants", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2014>4>b", "subject": "Agricultural Science Practical", "year": "2014", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PRODUCTION : CROP IMPROVEMENT", "question": "State three ways of controlling specimen R in crop production.", "images": [], "marking_scheme": "Use of scarecrow or bird scarer  Use of catapult  Use of avicides  Drumming or noise making on the farm.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2015>1>a>i", "subject": "Agricultural Science Practical", "year": "2015", "type": "Practical", "sub_label": "i", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL NUTRITION", "question": "Study specimens A (BONE), B (HORN), C (HOOF), D (WATER) and E (COWPEA) carefully and answer the following questions    State one major feed nutrient in each of specimens A and E", "images": [], "marking_scheme": "one major feed nutrient in each of specimens A and E    A: Mineral  E: Protein", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2015>1>a>ii", "subject": "Agricultural Science Practical", "year": "2015", "type": "Practical", "sub_label": "ii", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL NUTRITION", "question": "Study specimens A (BONE), B (HORN), C (HOOF), D (WATER) and E (COWPEA) carefully and answer the following questions  Mention three economic uses each of Specimens A, B, and C", "images": [], "marking_scheme": "A: Bone is processed as bone meal for livestock feed.  Bone is processed as bone meal for livestock feed  it is rich in calcium.  It can be used in the making of shoes.  Vaccines and hormones are Synthesized from bone.    Horns are used    for decorations  Horns can be used to make fertilizer because they are rich calcium and phosphorus  It can be used tor Livestock feed,  The animal also use it for fighting  C: Hoof:    it is used for gum and glue making.  Source of Income,  for employment,  use for room decoration   Making of buttons,", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2015>1>b>i", "subject": "Agricultural Science Practical", "year": "2015", "type": "Practical", "sub_label": "i", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL NUTRITION", "question": "Study specimens A (BONE), B (HORN), C (HOOF), D (WATER) and E (COWPEA) carefully and answer the following questions  State two functions of specimen D in farm animals", "images": [], "marking_scheme": "WATER ;    Water is for metabolic and digestion of food  it is used for dipping/drenching animals against ectoparasite and Washing of anirnals,  Cleaning of floors pens or for sanitation purposes.,  water is used for milk and meat processing water is part of the body  it is used for the maintenance of body temperature  water is used for irrigation of pasture  Water is a constituent of milk, egg, and meat.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2015>1>b>ii", "subject": "Agricultural Science Practical", "year": "2015", "type": "Practical", "sub_label": "ii", "group": "", "topic": "CROP PRODUCTION : CROP IMPROVEMENT", "question": "Study specimens A (BONE), B (HORN), C (HOOF), D (WATER) and E (COWPEA) carefully and answer the following questions  Highlight two benefits that a farmer would derive if specimen E is included in a crop rotation program.", "images": [], "marking_scheme": "Cow pea is a legume it will add nutrients to the soil.  It will turn atmospheric nitrogen to be available to plant.  it helps to control soil Erosion.  It also helps to conserve soil moisture.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2015>2>a", "subject": "Agricultural Science Practical", "year": "2015", "type": "Practical", "sub_label": "a", "group": "", "topic": "CROP PROTECTION : WEEDS", "question": "Study specimens G (GOAT WEED), H (SIDA WEED), I (SPEAR GRASS), J (ELEPHANT GRASS), and K (PIG WEED) carefully and answer the following questions.    State the botanical names of each of specimens G,H, I, J, and K.", "images": [], "marking_scheme": "G:Goat weed  Ageratum conizoides .  H:Sida weed  Sida acuta   I: Spear grass  Imperiata cylindrica   J:Elephant grass:  Penisetum purpureum   K:Pigweed  Boerhavia diffusa .", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2015>2>b", "subject": "Agricultural Science Practical", "year": "2015", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PROTECTION : WEEDS", "question": "Study specimens G (GOAT WEED), H (SIDA WEED), I (SPEAR GRASS), J (ELEPHANT GRASS), and K (PIG WEED) carefully and answer the following questions.  Give one reason why each of specimens I, J, and K is difficult to control.", "images": [], "marking_scheme": "It has an underground stem rhizome that produces new shoots from its axillary.  It has the ability to produce both roots and new shoots from each nodes.  It is propagated by stolon.  It is aggresive", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2015>2>c", "subject": "Agricultural Science Practical", "year": "2015", "type": "Practical", "sub_label": "c", "group": "", "topic": "CROP PROTECTION : WEEDS", "question": "Study specimens G (GOAT WEED), H (SIDA WEED), I (SPEAR GRASS), J (ELEPHANT GRASS), and K (PIG WEED) carefully and answer the following questions.  Mention two uses of specimen J", "images": [], "marking_scheme": "It selves as feed for Polygastric animals  It can be made into hay and silage for farm animals  The shoot can be used to make fence  The Shoot can be used to make mats, doors, and as fire Woods.  It can help to check soil erosion.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2015>2>d", "subject": "Agricultural Science Practical", "year": "2015", "type": "Practical", "sub_label": "d", "group": "", "topic": "CROP PROTECTION : WEEDS", "question": "Study specimens G (GOAT WEED), H (SIDA WEED), I (SPEAR GRASS), J (ELEPHANT GRASS), and K (PIG WEED) carefully and answer the following questions.  State five ways in which specimens G, H, I, J, and K are of economic importance to farmers.", "images": [], "marking_scheme": "Some are used in feeding farm animals  Some are used as medicine  They cover the surface of the soil.  They increase the cost of production in (Controlling them)  They compete with crops for nutrients, water, sunlight etc.", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2015>3>a", "subject": "Agricultural Science Practical", "year": "2015", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "Study specimens P ( Electric bulb) , Q (Garden fork), R (Hand trowel ) and S (knapsack sprayer) carefully and answer the following questions.    State two uses each of specimens P, Q, and R.", "images": [], "marking_scheme": "P:   It is used for lightening farmhouses,   It can also be used for brooding of chicks.   It can be used for candling of eggs.    Q: Hand Trowel:   It is used to apply fertilizer,   It is used to transplant seedling.   It is used for nursery practices & light Weeding,   It is used for digging holes for Garden fork.   It is used for turning manure during compost making.   It is used for loosening the soil before transplanting.   It is used for loading manure   It is used for loading hay.    R:It is used for transplanting seedliags for fertilizer and manure application for nursery practices and light weedings.     S:  It is used for spraying of insecticides, Pesticides etc.   It is used for watering of Vegetable beds.   It is used for spraying herbicides.", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2015>3>b", "subject": "Agricultural Science Practical", "year": "2015", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "Study specimens P ( Electric bulb) , Q (Garden fork), R (Hand trowel ) and S (knapsack sprayer) carefully and answer the following questions.  Mention three problems that may result from a poorly maintained specimen S.", "images": [], "marking_scheme": "The leftover chemicals make the knapsack sprayer to rust. The leftover chemical at the nozzle may block it. If it is not well drained the pipe may rust.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2015>3>c", "subject": "Agricultural Science Practical", "year": "2015", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "Study specimens P ( Electric bulb) , Q (Garden fork), R (Hand trowel ) and S (knapsack sprayer) carefully and answer the following questions.  List three protective devices that should be worn by a farmer when using specimen S.", "images": [], "marking_scheme": "Wearing of overall uniform, wearing of rain boot. Covering of the head and face with protective device eg face mask, should wear hand gloves during sprayíng.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2015>3>d", "subject": "Agricultural Science Practical", "year": "2015", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "Study specimens P ( Electric bulb) , Q (Garden fork), R (Hand trowel ) and S (knapsack sprayer) carefully and answer the following questions.  State three precautions that should be taken when using specimens S.", "images": [], "marking_scheme": "Operate according to instructions. Make sure you cover it very well. do not spray on a windy and raining day. pump the handle very well to Compress air to drive the spray.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2015>4>a", "subject": "Agricultural Science Practical", "year": "2015", "type": "Practical", "sub_label": "a", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "Study specimens V (EARTHWORM), W (PADDY RICE), X (GROUNDNUT SEEDS) and Y (MAIZE STEM BORER) carefully and answer the following questions.    State four ways in which specimen V is important in Agriculture.", "images": [], "marking_scheme": "It is important in agriculture because Earthworm aerate the soil. It helps to improve soil structure Through burrowing they leave holes for crop root penetration. They improve soil water percolation or drainage.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2015>4>b", "subject": "Agricultural Science Practical", "year": "2015", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "Study specimens V (EARTHWORM), W (PADDY RICE), X (GROUNDNUT SEEDS) and Y (MAIZE STEM BORER) carefully and answer the following questions.  Outline the steps involved in processing each of specimens W and X into polished rice and groundnut cake respectively.", "images": [], "marking_scheme": "W (PADDY RICE);    Sundrying: Dry the fresh rice for 3-4 days.  Threshing: use either manual or mechanical threshers to separate shafts from grains.  Winnowing: This is used to remove dust shafts from stalk or grains.  Parboiling: This is used to reduce breakage of grain, The paddy rice is boiled for about 12-15 hrs. The husks are easily removed   Hulling; This is the removal of the husks from the grains.  Polishing involves the use to specially designed machines to remove the husk and that layers Covering the grains polishing also involves removal of rice grain which is very Proteins and rich in Vitamins.    X (GROUNDNUT SEEDS)    Harvested nuts should be dried properly. The seeds are removed from the shells by Pounding them slightly with mortal or by beating them with sticks.  Small shelling or decorticating machine can be used to remove the seeds from the fruit", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2015>4>c", "subject": "Agricultural Science Practical", "year": "2015", "type": "Practical", "sub_label": "c", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "Study specimens V (EARTHWORM), W (PADDY RICE), X (GROUNDNUT SEEDS) and Y (MAIZE STEM BORER) carefully and answer the following questions.  Mention three measures used in controlling specimen Y on a farm", "images": [], "marking_scheme": "Plant resistant variety, early planting spray the farm with insectiales e.g. Gammalin 20. Uproot and burn the crop, practice crop rotation", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2016>1>a", "subject": "Agricultural Science Practical", "year": "2016", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT", "question": "The diagram above illustrates an experimental setup to determine a soil property.    Study them carefully and answer the question that follows;    Suggest a suitable title for the experiment", "images": ["Agricultural Science Practical/imgs/2016/XEMDRJ.png"], "marking_scheme": "To compare porosity water holding/ retaining capacity of different soil types", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2016>1>b", "subject": "Agricultural Science Practical", "year": "2016", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT", "question": "The diagram above illustrates an experimental setup to determine a soil property.    Study them carefully and answer the question that follows;  Outline the procedure for carrying out the experiment", "images": ["Agricultural Science Practical/imgs/2016/XEMDRJ.png"], "marking_scheme": "Procedure for carrying out the experiment    Obtain samples of sandy, clayey and loamy so-Dry them under the sun.  Grind loamy and clayey soils  Plug the necks of three funnels with cotton wool  Put equal volumes of sandy, clayey and loamy soils separately into three funnels plugged with cotton wool.  Tap the funnels carefully on the bench until all air spaces are filled with soil  Stand each funnel in the open end of a measuring cylinder.  Pour 50cm of water into the funnel containing each soil sample.  Allow the setup to settle for at least 1 hour.  Measure the amount of water that dripped through each soil sample.  By subtracting the amount of water that dripped through each soil sample, obtain the amount of water retained in each soil sample.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2016>1>c", "subject": "Agricultural Science Practical", "year": "2016", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT", "question": "The diagram above illustrates an experimental setup to determine a soil property.    Study them carefully and answer the question that follows;  identify the soil samples in diagrams I, II, and III", "images": ["Agricultural Science Practical/imgs/2016/XEMDRJ.png"], "marking_scheme": "Set up I - Loam/Loamy soil  Set up II - Sand/Sandy soil  Set up III- Clay/Clayey soil", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2016>1>d", "subject": "Agricultural Science Practical", "year": "2016", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT", "question": "The diagram above illustrates an experimental setup to determine a soil property.    Study them carefully and answer the question that follows;  State two precautions to be taken when carrying out the experiment.", "images": ["Agricultural Science Practical/imgs/2016/XEMDRJ.png"], "marking_scheme": "Precautions to be taken when carrying out the experiment     Soil samples should be dried under the sun   Loam and clay should be ground before use  The funnels should be properly plugged with tton wool to prevent soil samples from dripping into the measuring cylinders,  The funnels should be properly tapped to close ces that could distort the experiment.  Cylinders should be placed on flat and level surface.  Water should be poured into the cylinder at the all same time.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2016>1>e>i", "subject": "Agricultural Science Practical", "year": "2016", "type": "Practical", "sub_label": "i", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT", "question": "The diagram above illustrates an experimental setup to determine a soil property.    Study them carefully and answer the question that follows;  Which of the soil samples is prone to waterlogging?", "images": ["Agricultural Science Practical/imgs/2016/XEMDRJ.png"], "marking_scheme": "Soil sample in set up III (clay) is prone to waterlogging", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2016>1>e>ii", "subject": "Agricultural Science Practical", "year": "2016", "type": "Practical", "sub_label": "ii", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING", "question": "The diagram above illustrates an experimental setup to determine a soil property.    Study them carefully and answer the question that follows;  Give one reason for your answer in (e)(i)", "images": ["Agricultural Science Practical/imgs/2016/XEMDRJ.png"], "marking_scheme": "Presence of small pore spaces which do not allow water to drain easily/small fine particles", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2016>2>a", "subject": "Agricultural Science Practical", "year": "2016", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "Study specimens A (RANGING POLE), B (SURVEY PIN) and C (MEASURING TAPE) carefully and answer the following question.    Describe specimen A.", "images": [], "marking_scheme": "Description of specimen A (Ranging pole);    Made of wood or light metal  Could be in various lengths  Usually circular or round  Painted in black, white, orange/red  Painted divisions are in a specific measurement  Has a pointed metal end", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2016>2>b", "subject": "Agricultural Science Practical", "year": "2016", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "Study specimens A (RANGING POLE), B (SURVEY PIN) and C (MEASURING TAPE) carefully and answer the following question.  State two uses each of the specimens A, B and C.", "images": [], "marking_scheme": "Uses of specimen A (Ranging pole);    For marking survey stations.  To measure off set/ short distance.  for marking straight lines over long distances.    Uses of specimen B (Survey pin);    To make chain length.  To make survey stations/ points.  Uses of specimen C (Measuring tape)    For taking measurements of length, breadth and height  For taking off sets. triangles.  For determining straight lines and right-angled", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2016>2>c", "subject": "Agricultural Science Practical", "year": "2016", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : MAINTENANCE PRACTICES AND PRECAUTIONARY MEASURES", "question": "Study specimens A (RANGING POLE), B (SURVEY PIN) and C (MEASURING TAPE) carefully and answer the following question.  State two ways of maintaining each of specimens A, B, and C", "images": [], "marking_scheme": "Ways of maintaining specimens A, B and C    A (Ranging pole);    Oil the metal part after use to prevent rusting  Paint the bands when necessary  Sharpen the pointed end if blunt  Store in a cool dry place  B (Survey pin);    Sharpen the pointed end when blunt  Wipe with oil or grease after use when storing  Store in a cool dry place  Clean after use  C (Measuring tape);    Clean and dry after use/ wash and dry.  Roll back into the case after use.  Wipe steel tape with oil before storage.  Keep in a cool dry place.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2016>3>a>i", "subject": "Agricultural Science Practical", "year": "2016", "type": "Practical", "sub_label": "i", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "Study specimens G (GRASSHOPPER), H (BEAN BEETLE), I (BIRD), and J (RAT) carefully and answer the following questions.    Classify specimens G and H according to their feeding habits.", "images": [], "marking_scheme": "Classification of specimen G (Grasshopper) and H (Bean beetle) based on their feeding habits;    Specimen G (Grasshopper): biting and chewing insect pest  Specimen H (Bean beetle): boring insect pest", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2016>3>a>ii", "subject": "Agricultural Science Practical", "year": "2016", "type": "Practical", "sub_label": "ii", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "Study specimens G (GRASSHOPPER), H (BEAN BEETLE), I (BIRD), and J (RAT) carefully and answer the following questions.  Name one part of crops damaged by each of specimens G and H.", "images": [], "marking_scheme": "Part of crops damaged by specimens G and H;    G (Grasshopper): Leaf, young shoot, succulent stem  H (Bean beetle): Seeds", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2016>3>a>iii", "subject": "Agricultural Science Practical", "year": "2016", "type": "Practical", "sub_label": "iii", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "Study specimens G (GRASSHOPPER), H (BEAN BEETLE), I (BIRD), and J (RAT) carefully and answer the following questions.  State three ways in which specimen H is economically important", "images": [], "marking_scheme": "Ways in which specimen H (Bean beetle) is economically important    Destroys viability of seeds/destroys cotyledon.  Reduces market value of crop/quality of crop.  Increases farmer's cost of production.  Reduces the quantity of stored produce (seed)", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2016>3>b", "subject": "Agricultural Science Practical", "year": "2016", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "Study specimens G (GRASSHOPPER), H (BEAN BEETLE), I (BIRD), and J (RAT) carefully and answer the following questions.  State four ways of controlling each of specimens I and J", "images": [], "marking_scheme": "Ways of controlling Specimens I (Bird) J (Rat);    Specimen I (Bird);    Use of scarecrow/ bird scarer  Use of cage or string traps  Shooting with qun  Use of catapult  Drumming/noise making   Use of avicides/ poison  Specimen J (Rat);    Clean weeding of the farm  Trapping with baits  Use of rodenticides onno  Use of string or wire traps/ pit traps  Shooting with catapult  Smoking out of burrow/hole  Fencing Use of predators e.g. cat  Rat gum/mouse board", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2016>4>a", "subject": "Agricultural Science Practical", "year": "2016", "type": "Practical", "sub_label": "a", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "Study specimens N (BONE), O (EGG), P (ROUNDWORM) and Q (TICK) carefully and answer the following questions    Name three industries that use each of specimens N and O", "images": [], "marking_scheme": "Industries that use specimens N (Bone) and o (Egg);    Specimen N (Bone)    Livestock/animal feed-mill  Interior decoration industry  Fertilizer industries  Adhesive making industry  Pharmaceutical industry- vaccines and hormones  Ceramic industry  Shoemaking industry  Specimen O (Egg);    Confectionery/food industry  Pharmaceutical industry  Cosmetic industry  Feed mill  Hatchery industry  Meat processing industry as anti-oxidant", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2016>4>b", "subject": "Agricultural Science Practical", "year": "2016", "type": "Practical", "sub_label": "b", "group": "", "topic": "PARASITES", "question": "Study specimens N (BONE), O (EGG), P (ROUNDWORM) and Q (TICK) carefully and answer the following questions  State five effects of specimen P on the host.", "images": [], "marking_scheme": "Effects of specimen P (Roundworm) on the host    Internal haemorrhage/anaemia   Loss of weight/emaciation  Loss of appetite  Constipation/digestive problems in the body  Weakness  Reduction in livestock productivity  May cause death  Damage to the internal organ during migration of young ones", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2016>4>c", "subject": "Agricultural Science Practical", "year": "2016", "type": "Practical", "sub_label": "c", "group": "", "topic": "PARASITES", "question": "Study specimens N (BONE), O (EGG), P (ROUNDWORM) and Q (TICK) carefully and answer the following questions  State four ways of controlling specimen Q on the farm.", "images": [], "marking_scheme": "Ways of controlling specimen Q (Tick) on the farm    Dipping the animal in acaricide solution  Spraying the animal with acaricides  Rotational grazing/ paddocking  Burning of infested pasture  Quarantining new stock before being mixed with the existing stock  Good sanitation practices  Hand-picking and destroying the ticks  Use of predators e.g. cattle egret", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2017>1>a>i", "subject": "Agricultural Science Practical", "year": "2017", "type": "Practical", "sub_label": "i", "group": "", "topic": "AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE", "question": "Study specimen E (NPK 15:15:15, F (WOOD ASH), G (LIMESTONE), and H (COWDUNG) and answer the following questions.    State three major nutrients supplied to crops by specimen E", "images": [], "marking_scheme": "Major nutrients supplied by specimen E (NPK 15:15:15) -    Nitrogen  Phosphorus  Potassium", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2017>1>a>ii", "subject": "Agricultural Science Practical", "year": "2017", "type": "Practical", "sub_label": "ii", "group": "", "topic": "AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE", "question": "Study specimen E (NPK 15:15:15, F (WOOD ASH), G (LIMESTONE), and H (COWDUNG) and answer the following questions.  List three methods that could be used to apply specimen E on a farm", "images": [], "marking_scheme": "Methods that could be used to apply specimen E (NPK 15:15:15) on a farm -    Ring Method Side dressing/placement/row placement  Top dressing  Broadcasting  Foliar spray/ fertigation  Band placement", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2017>1>b", "subject": "Agricultural Science Practical", "year": "2017", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE", "question": "Study specimen E (NPK 15:15:15, F (WOOD ASH), G (LIMESTONE), and H (COWDUNG) and answer the following questions.  State three agricultural uses of each of specimens F and G", "images": [], "marking_scheme": "Agricultural uses of specimen F and G    Specimen F (Wood ash);    Liming material to correct soil acidity  Sprinkled on crops to control insect pests  Provides nutrients (Potassium) for crop growth  Used to correct acidity in fish pond  Used in compost making  Increases growth to phytoplankton in fish ponds  Used in controlling pond algae  Used to increase the rate of percolation in clay soil   Specimen G (Limestone) -    Supplies calcium for crop growth/adds nutrients to the soil  Added to the soil to improve its structure  Used to correct acidity in fish pond water  Used to reduce turbidity in fish ponds  Used to reduce soil acidity/1iming material  Applied to clay to release locked-up nutrients the soil", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2017>1>c", "subject": "Agricultural Science Practical", "year": "2017", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT", "question": "Study specimen E (NPK 15:15:15, F (WOOD ASH), G (LIMESTONE), and H (COWDUNG) and answer the following questions.  Mention three ways in which specimen H is important to the soil", "images": [], "marking_scheme": "Importance of specimen H (Cow dung) to the soil;    Adds nutrients to the soil    Improves soil structure    Improves activities of soil microbes    Improves soil water holding capacity    Prevent rapid changes in temperature    Provides buffering effect on the soil pH    Improves soil aeration when it decomposes", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2017>2>a>i", "subject": "Agricultural Science Practical", "year": "2017", "type": "Practical", "sub_label": "i", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "Study specimens I (WHEELBARROW), J (FILE), K (PALM OIL) and L (COTTON LINT) carefully and answer the following questions.    Give two uses each of specimens I and J", "images": [], "marking_scheme": "Uses of specimens I and J    Specimen I (Wheelbarrow) -    For transporting farm inputs e.g. seeds, seedlings, feeds, fertilizer around a farm  For transporting farm produce e.g. harvested crops, animal produce  For carrying farm tools and working materials around a farm  For carrying farm refuse out of the farm  Specimen J (File) -    For sharpening blade of farm tools  For smoothening rough surfaces of farm implements", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2017>2>a>ii", "subject": "Agricultural Science Practical", "year": "2017", "type": "Practical", "sub_label": "ii", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS", "question": "Study specimens I (WHEELBARROW), J (FILE), K (PALM OIL) and L (COTTON LINT) carefully and answer the following questions.  State two general ways of maintaining specimens I and J", "images": [], "marking_scheme": "General ways of maintaining specimens I (Wheelbarrow) and J (File) -    Clean after use/wash and dry after use  Replace worn-out parts  Store/keep in cool, dry place  Paint/greases to prevent rusting of metal parts  Keep wooden handle away from termites", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2017>2>b>i", "subject": "Agricultural Science Practical", "year": "2017", "type": "Practical", "sub_label": "i", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "Study specimens I (WHEELBARROW), J (FILE), K (PALM OIL) and L (COTTON LINT) carefully and answer the following questions.  Give the botanical names of the crops from which, each of specimens K and L were obtained", "images": [], "marking_scheme": "Botanical names of crops from which specimens K(Palm oil) and L (Cotton lint) were obtained    Specimen K: Elaeis guincensis  Specimen L: Gossypium spp/ Any specific species", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2017>2>b>ii", "subject": "Agricultural Science Practical", "year": "2017", "type": "Practical", "sub_label": "ii", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "Study specimens I (WHEELBARROW), J (FILE), K (PALM OIL) and L (COTTON LINT) carefully and answer the following questions.  Outline the steps involved in the traditional method of producing specimen K", "images": [], "marking_scheme": "Steps involved in the traditional method of producing specimen K( Palm oil) -    Boil the fruits  Pound the boiled fruits in a mortar  Add water to the mixture  Stir the mixture vigorously  Wash and remove the fibre/nuts  Separate the oil from water by floatation  Boil the crude liquid  Separate the oil from water  Re-heat the oil to eliminate any trace of water by evaporation", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2017>3>a>i", "subject": "Agricultural Science Practical", "year": "2017", "type": "Practical", "sub_label": "i", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "Study specimens P (APHID),Q (COWPEA SEEDS) and R (COCONUT FRIUT)and answer the following questions;    State three effects of specimen P on crops", "images": [], "marking_scheme": "Effects of specimen P (Aphid) on crops -    Causes stunted growth  Reduces the yield of crops  Transmits diseases to crops/vector of diseases  It produces Honey dew which covers the leaves of crops and reduces photosynthesis  Piercing through outer tissues and sucking nutritional sap", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2017>3>a>ii", "subject": "Agricultural Science Practical", "year": "2017", "type": "Practical", "sub_label": "ii", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "Study specimens P (APHID),Q (COWPEA SEEDS) and R (COCONUT FRIUT)and answer the following questions;  Mention two ways of controlling specimen P", "images": [], "marking_scheme": "Ways of controlling specimen P (Aphid) -    Use of lady bird beetle  Spray with insecticides  Uproot and burn infected plants  Hand picking of adult aphid and nymphs and destroying them", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2017>3>b>i", "subject": "Agricultural Science Practical", "year": "2017", "type": "Practical", "sub_label": "i", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "Study specimens P (APHID),Q (COWPEA SEEDS) and R (COCONUT FRIUT)and answer the following questions;  Give two benefits of including the crop from which specimen Q was obtained in a mixed cropping system", "images": [], "marking_scheme": "Benefits of including the crop from which specimen Q (cowpea seeds) were obtained in a mixed cropping system    Covers the soil thereby protecting it against erosion  Adds nitrogen to the soil  Helps to smother weeds  Serves as source of fodder after harvesting", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2017>3>b>ii", "subject": "Agricultural Science Practical", "year": "2017", "type": "Practical", "sub_label": "ii", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "Study specimens P (APHID),Q (COWPEA SEEDS) and R (COCONUT FRIUT)and answer the following questions;  Name the major storage pest of specimen Q", "images": [], "marking_scheme": "Major storage pest of specimen Q(Cowpea seeds); Bean beetle", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2017>3>c", "subject": "Agricultural Science Practical", "year": "2017", "type": "Practical", "sub_label": "c", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL NUTRITION", "question": "State five uses of specimen R", "images": [], "marking_scheme": "Uses of specimen R (Coconut fruit);    Eaten as food by humans  Fed to farm animals  Processed to obtain vegetable oil/coconut oil  Source of fibre should be used as fuel/in making foot mat and brush  Source of coconut water used to produce fruit juice  Shell is used as abrasive  Coconut water is used as medicine  Used for crafts/decoration  Raw material for industries e.g. cosmetic industry", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2017>3>d", "subject": "Agricultural Science Practical", "year": "2017", "type": "Practical", "sub_label": "d", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "Give the botanical names of the crops from which specimens Q and R were obtained.", "images": [], "marking_scheme": "Botanical names of the crops from which specimens Q(Cowpea seeds) and R (Coconut fruit) were obtained;    Specimen Q:  Vigna unguiculata   Specimen R:  Cocos nucifera", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2017>4>a>i", "subject": "Agricultural Science Practical", "year": "2017", "type": "Practical", "sub_label": "i", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL IMPROVEMENT", "question": "Study specimens T (CHICKEN EGG) and U (TILIPIA FISH) and answer the following questions;    Name three breeds of the farm animal which produces specimen T", "images": [], "marking_scheme": "Breeds of the farm animal which produces specimen T (Chicken egg) -    Rhode island red  White leghorn  Brown leghorn  Nera black  Cornish  Sussex  Cochin  New Hampshire  Plymouth rock  Black leghorn", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2017>4>a>ii", "subject": "Agricultural Science Practical", "year": "2017", "type": "Practical", "sub_label": "ii", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL NUTRITION", "question": "Study specimens T (CHICKEN EGG) and U (TILIPIA FISH) and answer the following questions;  State four ways in which specimen T is economically important", "images": [], "marking_scheme": "Ways in which specimen T (Chicken egg) is economically important ;    Eaten as food by humans   Egg shell is a source of Calcium in farm animal feeds Source of income to farmers and traders  Used in making confectioneries/ baking  Used as raw material in pharmaceutical/cosmetic industries  Egg production/sale is a source of employment  Used in the production of chicks  Used in producing vaccines  Used in making adhesives/binding agent", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2017>4>b>i", "subject": "Agricultural Science Practical", "year": "2017", "type": "Practical", "sub_label": "i", "group": "", "topic": "ANIMAL PRODUCTION : AQUACULTURE", "question": "Study specimens T (CHICKEN EGG) and U (TILIPIA FISH) and answer the following questions;  Mention two methods of harvesting specimen U, from the pond", "images": [], "marking_scheme": "Methods of harvesting specimen U (Tilapia fish) from the pond -    Hook and line  Fishing nets e.g scoop net, gill net, seine net etc  Fishing baskets  Fishing traps  Harpoon/fishing spear  Draining of pond", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2017>4>b>ii", "subject": "Agricultural Science Practical", "year": "2017", "type": "Practical", "sub_label": "ii", "group": "", "topic": "ANIMAL PRODUCTION : AQUACULTURE", "question": "Study specimens T (CHICKEN EGG) and U (TILIPIA FISH) and answer the following questions;  List two by-products that could be obtained from the processing of specimen U", "images": [], "marking_scheme": "By-products that could be obtained from thedbo processing of specimen U (Tilapia fish)    fish bone  Fishmeal  Fish scale  Fish oil  Fish skin", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2017>4>b>iii", "subject": "Agricultural Science Practical", "year": "2017", "type": "Practical", "sub_label": "iii", "group": "", "topic": "ANIMAL PRODUCTION : AQUACULTURE", "question": "Study specimens T (CHICKEN EGG) and U (TILIPIA FISH) and answer the following questions;  State four methods of preserving specimen U", "images": [], "marking_scheme": "Methods of preserving specimen U (Tilapia fish) -    Sun drying  Salting   Smoking  Canning  Freezing/Refrigeration  Oven-drying  Frying", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2018>1>a", "subject": "Agricultural Science Practical", "year": "2018", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "State three uses of each of specimens A (AXE), B(SPADE), D(HAND TROWEL) and F(HAND FORK)", "images": [], "marking_scheme": "Uses of specimens A (Axe), B (Spade), D (Hand trowel) and F (Hand fork)     A (Axe)    Forfelling trees  Cutting stumps / uprooting stumps/ stumping  Cutting roots  Splitting wood / chopping wood / hewing of wood  For pruning, e.g. palm frond  For harvesting palm fruit  Cutting firewood   B (Spade)    Used in turning soil  Digging soil for transplanting  Mixing manure /spreading manure  Making mounds or ridges or heaps/ seed bed making  Mixing cement/ concrete for farm structures  Mixing animal feed  Removal of animal wastes  Levelling soil surface  For mixing soils and fertiliser  For harvesting crops  For light weeding  D(Hand trowel)    Transplanting seedlings  Used in fertiliser application / manure application  Loosening vegetable beds  Light weeding  For mixing soil and fertiliser  Digging holes for planting  F (Hand fork)    Loosening surface soil / breaking soil clods  Light weeding  Mixing small quantities of soil / manure  Working manure into soil", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2018>1>b", "subject": "Agricultural Science Practical", "year": "2018", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : MAINTENANCE PRACTICES AND PRECAUTIONARY MEASURES", "question": "State three ways of maintaining specimen A.", "images": [], "marking_scheme": "Ways of maintaining specimen A (Axe)    Sharpen blunt edge  Keep wooden handle away from fire and termite  Clean after use / wash and dry  Rub metal blade with oil/ grease metal to avoid corrosion after use  Store in a cool, dry place", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2018>2>a", "subject": "Agricultural Science Practical", "year": "2018", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT", "question": "With the aid of the litmus paper and water provided, classify specimens G, H and I.", "images": [], "marking_scheme": "Classification of specimens G, H and I according to their pH    Specimen G- neutral soil    H- acidic soil  I- alkaline/ basic soil", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2018>2>b", "subject": "Agricultural Science Practical", "year": "2018", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "Outline the steps taken in classifying specimen G (NEUTRAL SOIL), H (ACIDIC SOIL) and I (ALKALINE / BASIC SOIL)", "images": [], "marking_scheme": "Steps taken in classifying specimens G, H and I    Add some quantity of water to each of specimens G, H and I.  Stir thoroughly.  Test each of the specimens with litmus papers  Specimen G- no change in colour of litmus paper neutral  Specimen H- blue litmus paper turned red- acidic  Specimen I-red litmus paper turned blue - alkaline/ basic", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2018>2>c>i", "subject": "Agricultural Science Practical", "year": "2018", "type": "Practical", "sub_label": "i", "group": "", "topic": "AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "If the pH value of one of the soil samples provided is 4.5, what condition does this pH value indicate in the soil sample?", "images": [], "marking_scheme": "Condition indicated by pH value of 4.5; Soil acidity", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2018>2>c>ii", "subject": "Agricultural Science Practical", "year": "2018", "type": "Practical", "sub_label": "ii", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "State three effects of the condition indicated in (c)(i) on crop production.", "images": [], "marking_scheme": "Effects of soil acidity on crop production    Could damage the roots of plants  Hinders the absorption of mineral ions  Lowers the rate of decomposition of organic matter due to its adverse effects on soil micro-organisms  Humus could easily be leached out of the soil.  Causes nutrient deficiency especially calcium - and phosphorus  Causes certain nutrients to be present in the soil in toxic levels, e.g. manganese and iron  Depresses nitrification because of its adverse effect on soil microbes/ low pH reduces the activities of soil micro-organisms  Reduces microbial population  Low pH reduces the formation of pods in legumes.  It causes reduced growth and yield of crops.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2018>2>c>iii", "subject": "Agricultural Science Practical", "year": "2018", "type": "Practical", "sub_label": "iii", "group": "", "topic": "AGRICULTURAL ECOLOGY : ENVIRONMENTAL FACTORS AFFECTING CROP AND ANIMAL DISTRIBUTION AND PRODUCTION", "question": "List Three factors that could cause the condition indicated in (c)(i).", "images": [], "marking_scheme": "Factors that could cause soil acidity    Absorption of basic cations / Nutrient uptake by plants  Use of nitrogen/ sulphur-based fertilizers  Leaching  Erosion  Acidic parent material  Acid rains in industrial areas  Presence of sulphur in the soil leads to the formation of weak acid.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2018>3>a", "subject": "Agricultural Science Practical", "year": "2018", "type": "Practical", "sub_label": "a", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "Name the organism which causes the damage observe on each of specimen J, K, L and M.", "images": [], "marking_scheme": "Organisms which cause the damage observed in specimens J,K,L and M    Specimen J- Maize weevil  Specimen K- Yam beetle  Specimen L-Virus  Specimen M- Fungus", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2018>3>b", "subject": "Agricultural Science Practical", "year": "2018", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "State three ways in which the organism which caused the damage on specimen J is of economic importance.", "images": [], "marking_scheme": "Economic importance of maize weevil    Causes loss of food/ food shortage/destruction of stored maize  Destruction of seed viability/ reduced seed germination  Causes loss of income/ reduced market value  Increases the cost of production due to the cost of controlling the pest  It reduces yield/quantity of produce.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2018>3>c", "subject": "Agricultural Science Practical", "year": "2018", "type": "Practical", "sub_label": "c", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "State two ways of controlling each of the organisms which caused damage to specimens J,K, L and M.", "images": [], "marking_scheme": "Ways of controlling maize weevil, yam beetle, cassava mosaic virus and fruit rot of tomato    Maize weevil;    Use of dry hot pepper/ use of pepper  Store in air tight containers  Use of appropriate insecticide  Heat treatment/ store on rafters in smoky rooms  Use of deep freezer/freezing  Early harvesting of crops  Fumigating maize in store  Yam beetle;    Treat yam setts/ seeds yams with appropriate insecticides  Crop rotation  Late planting  Hand-picking and destroying  Dust yam set with alum dust.  Cassava mosaic virus;     Plant resistant varieties  Uproot and burn infected plants  Farm sanitation  Plant clean and disease-free stem cuttings  Spray insecticides to kill the vectors  Fruit rot fungus;    Use of resistant varieties  Remove infected plants  Staking of tomato plants.  Treating soil with copper-based fungicide.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2018>4>a", "subject": "Agricultural Science Practical", "year": "2018", "type": "Practical", "sub_label": "a", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT", "question": "Name three farm animal hosts of specimen O (TICK)", "images": [], "marking_scheme": "Farm Animal hosts of Specimen O (Tick)    Cattle  Sheep  Goat  Donkey  Horse  Dog  Pig  Camel", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2018>4>b", "subject": "Agricultural Science Practical", "year": "2018", "type": "Practical", "sub_label": "b", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT", "question": "State four damages done by each of specimens N (LIVER FLUKE) and O on their farm animal hosts", "images": [], "marking_scheme": "Damages done by Specimen N (Liver fluke) and O (Tick)    Specimen N(Liver fluke);    Anaemia / Loss or sucking of blood  Blocking of bile duct  Loss of weight / emaciation    May cause internal bleeding / internal haemorrhage  Burrow into the liver / damage the liver  Weakness of animal   Loss of appetite  May lead to death  It causes digestive problem to host  Specimen O (Tick);    Disease transmission  Loss of blood/ anaemia  Body irritation / restlessness / tick worry  Reduced quality of skin / hide  Emaciation/loss of weight  Wound created may lead to secondary infection", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2018>4>c", "subject": "Agricultural Science Practical", "year": "2018", "type": "Practical", "sub_label": "c", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT", "question": "Enumerate four ways of controlling specimen O", "images": [], "marking_scheme": "Ways of controlling Specimen O (Tick)    Quarantine  Rotational grazing / paddocking  Use of acaricide  Hand picking on a small scale  Dipping  Burn infested pasture/ grazing land  Spraying  Drenching  Proper sanitation/ changing animal bedding regularly  Destruction of wild animals around the farm that can serve as alternate hosts", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2019>1>a", "subject": "Agricultural Science Practical", "year": "2019", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "State three uses each of specimens A (RAKE), C (SHOVEL), and D (CUTLASS)", "images": [], "marking_scheme": "Uses of specimens A(Rake), C (Shovel) and D (Cutlass)    A (Rake)    removing rubbish from the farm  levelling of soil surface-breaking soil lump into smaller particles  spreading grains and beans When sun-drying  Covering vegetable seeds when broadcasted  spreading manure-removing stones from seedbeds  C(Shovel)    transferring soil from one place to another  light weeding on the farm  loading materials into wheelbarrow  making mounds/heaps/ridges  removing stones and rubbish  mixing soil and cement together in Constructing farm buildings  harvesting of root/tuber crops   excavation or digging of the soil  making garden paths  levelling the ground  D (Cutlass)    clearing and slashing bushes  planting/sowing  felling trees  digging holes for the fixing of fence poles  havesting crops like coconut, banana, pineapple, sugarcane  light digging like transplanting  for weeding  pruning tree crops", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2019>1>b", "subject": "Agricultural Science Practical", "year": "2019", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "Describe Specimen E (WHEELBARROW).", "images": [], "marking_scheme": "Description of specimen E (Wheelbarrow)    Consists of a large metal basin/container  Has a metal wheel which is made of steel bearing and rubber tyre  Has two short legs at the back for support while resting on the ground  Has two long handles for pulling and pushing", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2019>1>c", "subject": "Agricultural Science Practical", "year": "2019", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "State three ways of maintaining Specimen E", "images": [], "marking_scheme": "Ways of maintaining specimenE (Wheelbarrow)    Wash and dry/clean after use  Check the tyre pressure and inflate when necessary  Tighten loose bolts and nuts regularly  Paint the metal parts  Store in a cool, dry place  Lubricate moving parts/wheel bearing  Replace damaged parts", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2019>2>a", "subject": "Agricultural Science Practical", "year": "2019", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "Take a sample each of specimens F (CLAY SOIL), G (LOAMY SOIL) and H (SANDY SOIL) and rub each between the thumb and forefinger. Put a sample of each of the specimens on your palm and add a little amount of water sufficient to wet it. Mix each sample with water. Attempt producing a roll and then a ring.    Tabulate your observations from the experiment", "images": [], "marking_scheme": "Tabulation of observation from the experiment  F (Clay Soil)G (Loamy Soil)H (Sandy Soil)smooth/powdery to touchintermediate/neither smooth nor coarsecoarse/gritty to touchsticky when wetnot sticky when wetnot sticky when weta roll was producedformed a weak rollno roll was producedmoderately plasticnot plasticfine/tiny grainsa ring was formed", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2019>2>b", "subject": "Agricultural Science Practical", "year": "2019", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PRODUCTION : CLASSIFICATION OF CROPS", "question": "Name two crops that can be grown on specimen H", "images": [], "marking_scheme": "Crops that can be grown on specimen H (Sandy soil)    Groundnut  Cowpea  Soybean  Millet Coconut  Oil palm  Cotton  Sugarcane  Guinea corn  Pigeon pea  Watermelon", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2019>2>c>i", "subject": "Agricultural Science Practical", "year": "2019", "type": "Practical", "sub_label": "i", "group": "", "topic": "AGRICULTURAL ECOLOGY : ENVIRONMENTAL FACTORS AFFECTING CROP AND ANIMAL DISTRIBUTION AND PRODUCTION", "question": "Which of specimens F,G, and H is preferred for maize productions?", "images": [], "marking_scheme": "Preferred specimen for maize production - Specimen G (Loamy soil)", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2019>2>c>ii", "subject": "Agricultural Science Practical", "year": "2019", "type": "Practical", "sub_label": "ii", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT", "question": "Give three reasons for your answers in (c)(i).", "images": [], "marking_scheme": "Reasons why specimen G (Loamy soil is preferred for maize production)    It has good aeration  Contains high organic matter  Leaching of nutrients is minimized  Easy to cultivate  Has a crumby structure  Has good water retention capacity  Encourages microbial activities  It is well-drained", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2019>2>d", "subject": "Agricultural Science Practical", "year": "2019", "type": "Practical", "sub_label": "d", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "State three ways in which specimen l (EARTHWORM) is of economic importance in agriculture.", "images": [], "marking_scheme": "Economic importance of specimen I (Earthworm) in agriculture    Improves soil aeration  Adds organic matter to soils/improves soil fertility  Improves microbial activities on soil  Improves soil structure and granulation  Aids in the decomposition of organic matter in the soil  Increases the rate of water percolation in soils  Aids plant root penetration by burrowing  Improves the cation exchange capacity of soils  Increases the level of nutrients in the soil  Used as bait for catching fish  Pulverises the soil by mixing top soil with the subsoil  Stabilizes soil pH through the addition of organic matter", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2019>3>a", "subject": "Agricultural Science Practical", "year": "2019", "type": "Practical", "sub_label": "a", "group": "", "topic": "CROP PRODUCTION : CLASSIFICATION OF CROPS", "question": "Using a table, classify specimens J, K, L, M, N and O into the following crops groups: Fruit, Leafy vegetable, Bulb and Root.", "images": [], "marking_scheme": "Classification of specimens into crop groups  FruitLeafy VegetableBulbRootTomato (K)Amaranthus (M)Onion (J)Carrot (L)Okro (N)Spinach (O)", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2019>3>b", "subject": "Agricultural Science Practical", "year": "2019", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "List five general cultural practices that are carried out by farmers when growing Specimens J, K, L, M, N and O.", "images": [], "marking_scheme": "General cultural practices that are carried out by farmers when growing specimens J, K, L M,N and O    Watering  Weeding  Mulching  Fertliser application/manuring  Pest control  Thinning  Supplying/filing in  Disease control  Roguing", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2019>3>c", "subject": "Agricultural Science Practical", "year": "2019", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ECOLOGY : AGRO-ALLIED INDUSTRIES AND RELATIONSHIP BETWEEN AGRICULTURE AND INDUSTRY", "question": "State four ways in which the growing of Specimens J, K, L, M, N and is important to humans.", "images": [], "marking_scheme": "Importance of specimens J. K, L, M, N and O to humans    Provide income for the farmer  Provide raw materials for agro based industries  Provide vitamins in human diets  Provide foreign exchange  Provide employment  They are medicinal", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2019>4>a", "subject": "Agricultural Science Practical", "year": "2019", "type": "Practical", "sub_label": "a", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL NUTRITION", "question": "State the main food nutrient obtainable from specimen Q (BONE MEAL) and two main food nutrients obtainable from Specimen S(CATFISH)", "images": [], "marking_scheme": "Main food nutrients obtainable from specimen Q (Bone Meal) and S (Catfish);    Specimen Q ;    Calcium  Phosphorus  Specimen S;    Protein  Fats and Oil", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2019>4>b", "subject": "Agricultural Science Practical", "year": "2019", "type": "Practical", "sub_label": "b", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL NUTRITION", "question": "State three functions of each of the two main nutrients obtainable from specimen S mentioned in (a).", "images": [], "marking_scheme": "Functions of the main nutrients obtainable from specimen s (Catfish)    Proteins;    For growth and bodybuilding  Repair of damaged tissues  Replacement of worn-out body tissues  Synthesis of enzymes, hormones and other body fluids  Formation of animal products such as milk, eggs, wool, fur, feather.    Fats and oil;    For insulation/conservation of body heat  Act as carriers of fat-soluble vitamins/solvent for vitamins A, D, E and K  Protects organs such as intestines, kidneys  Source of energy  Medicinal  Provision of essential fatty acids", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2019>4>c", "subject": "Agricultural Science Practical", "year": "2019", "type": "Practical", "sub_label": "c", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "Name three farm animals from which specimen Q could be obtained.", "images": [], "marking_scheme": "Farm animals from which specimens Q(Bone meal) could be obtained    Cattle  Sheep  Goat  Pig  Rabbits  All classes of poultry", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2019>4>d", "subject": "Agricultural Science Practical", "year": "2019", "type": "Practical", "sub_label": "d", "group": "", "topic": "ANIMAL PRODUCTION : ANIMAL NUTRITION", "question": "Give three disadvantages of using the ingredients prepared from specimen P (BLOOD MEAL) in compounding livestock feed", "images": [], "marking_scheme": "Disadvantages of using the ingredient prepared from dried animal blood (blood meal) in compounding livestock feed    Could be a source of disease infection  Invites a lot of flies-Has low palatability  Easily contaminated/adulterated  Poor storage ability  Repulsive odour", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2020>1>a", "subject": "Agricultural Science Practical", "year": "2020", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "State two uses each of specimens A (HOE) and B(PICK AXE)", "images": [], "marking_scheme": "Uses of specimens A (Hoe) and B (Pick axe);    A(Hoe);    Loosening the soil;  Uprooting weeds/weeding;  Harvesting of crops e.g. groundnut and yam;  Making ridges/heaps/mounds/seed bed;  Planting/transplanting of some crops.  B (PickAxe):    Breaking up hard ground/ loosening the soil;  Stumping/uprooting of trees and stones;  For making ridges;  For tilling soil for farm building erection;  Digging hole, pits", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2020>1>b", "subject": "Agricultural Science Practical", "year": "2020", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "Name four crops that require the use of specimen D (BUDDING KNIFE) during propagation.", "images": [], "marking_scheme": "Crops that require the use of specimen D(Budding knife) during propagation:    Mango,  Citrus,  Avocado pear,  Cashew,  Apple,  Cherry,  Rubber,  Cocoa,  Coffee,  Kola,  Walnut,  Plum", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2020>1>c", "subject": "Agricultural Science Practical", "year": "2020", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "Name three other tools that could serve the same purpose as specimen E (BURDIZZO).", "images": [], "marking_scheme": "Other tools that could serve the same purpose as Specimen E (Burdizzo):    Sharp knife,  Emasculator,  Scalpel,  Hemostat,  Razor blade,  Elastrator,  Forceps,  Pincers.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2020>1>d", "subject": "Agricultural Science Practical", "year": "2020", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : MAINTENANCE PRACTICES AND PRECAUTIONARY MEASURES", "question": "Mention four ways of maintaining specimen A (HOE)  on the farm.", "images": [], "marking_scheme": "Ways of maintaining specimen A (Hoe) on the farm:-    Wash and dry/clean after use,  Store in cool, dry place,  Straighten bent blade,  Keep wooden handle away from termite attack,  Replace worn out parts,  Oil/grease metal blade before storage,  Sharpen the blunt blade", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2020>2>a", "subject": "Agricultural Science Practical", "year": "2020", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT", "question": "What is the aim of the experimental set-up F?", "images": [], "marking_scheme": "Aim of the experiment set-up F:     Determination of Soil texture by sedimentation/sedimentation experiment", "marks": "1", "difficulty": "3"}, {"id": "theory>Agricultural Science Practical>2020>2>b", "subject": "Agricultural Science Practical", "year": "2020", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT~~AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "List three materials that could be used in carrying out the experiment in the set-up F.", "images": [], "marking_scheme": "Materials that could be used in carrying out the experiment in the set-up F:    Soil sample,  Measuring cylinder,  Beaker,  Glass jar,  Water,  Glass rod/ stirrer,  Hydrogen peroxide/Calgon", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2020>2>c", "subject": "Agricultural Science Practical", "year": "2020", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT~~AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "Outline three steps invołved in carrying out the experiment.", "images": [], "marking_scheme": "Steps involved in carrying out the experiment:    Put a quantity of soil sample in the measuring cylinder,  Water is added to the soil sample in the measuring cylinder,  Hydrogen peroxide could be added to break soil lumps,  The content in the measuring cylinder is n stirred with a glass rod/shake vigorously,  The content is allowed to settle for some hours.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2020>2>d", "subject": "Agricultural Science Practical", "year": "2020", "type": "Practical", "sub_label": "d", "group": "", "topic": "AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL", "question": "Name four soil components observed in the experimental set-up.", "images": [], "marking_scheme": "Soil components observed in the experimental set-up:    Coarse sand,  Silt, Water,  Fine sand,  Clay,  Organic matter", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2020>2>e", "subject": "Agricultural Science Practical", "year": "2020", "type": "Practical", "sub_label": "e", "group": "", "topic": "AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT", "question": "Draw and label the experimental set-up.", "images": ["Agricultural Science Practical/imgs/2020/GMHF66.jpg"], "marking_scheme": "", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2020>3>a>i", "subject": "Agricultural Science Practical", "year": "2020", "type": "Practical", "sub_label": "i", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "Name the toxic substance found in specimen G (FRESH CASSAVA TUBER).", "images": [], "marking_scheme": "Name of toxic substance found in specimen G (Fresh cassava tuber):    - Hydrogen cyanide/cyanide/prussic acid/Hydrocyanic.", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2020>3>a>ii", "subject": "Agricultural Science Practical", "year": "2020", "type": "Practical", "sub_label": "ii", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "Suggest four ways of removing the toxic substance named in (a)(i).", "images": [], "marking_scheme": "Ways of removing hydrogen cyanide in fresh cassava tubers:    Grating the tubers and squeezing out the water under pressure for few days  Soaking the tubers in water for some days/ fermentation,  Drying the soaked tubers in water for some days/fermentation,  Drying the soaked tubers in the sun,  Boiling/cooking the tubers,  Frying.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2020>3>b", "subject": "Agricultural Science Practical", "year": "2020", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "State two uses each of specimens I (ONION BULBS) and J (PEPPER FRUITS).", "images": [], "marking_scheme": "Uses of specimen I (Onion bulbs) and J (Pepper fruits):    I (Onion bulbs);    Sources of vitamins A and C.  For flavouring food,  Medicinal uses,  Source of volatile oil,  Eaten as food,  Antioxidant,  Boost digestion,  Nourish the skin,   To repel snakes around the home.  J(Pepper fruits):    Spice for food,  Insect repellant in stored produce,  Medicinal uses,  Used as yolk colourant,  Source of antioxidant (piperine),  Used in tear gas to disperse crowds/ as pepper spray.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2020>3>c", "subject": "Agricultural Science Practical", "year": "2020", "type": "Practical", "sub_label": "c", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "List four pests of specimen I.", "images": [], "marking_scheme": "Pest of specimen L (Onion bulbs):    Grasshopper.  Cricket,  Cockroach,  Monkey,  Thrips,  Rat/Rodents,  Maggot.   Eelworm", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2020>3>d", "subject": "Agricultural Science Practical", "year": "2020", "type": "Practical", "sub_label": "d", "group": "", "topic": "CROP PRODUCTION : CLASSIFICATION OF CROPS", "question": "Name two groups of crops to which specimens I and J belong based on their uses.", "images": [], "marking_scheme": "Group of crops to which specimens I(Onion bulbs) and J (Pepper fruits) belong based on their uses;    Spices  Vegetables", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2020>4>a", "subject": "Agricultural Science Practical", "year": "2020", "type": "Practical", "sub_label": "a", "group": "", "topic": "ANIMAL PRODUCTION : AQUACULTURE", "question": "Give three reasons for stocking K (TILAPIA) and L (CATFISH) together in a pond.", "images": [], "marking_scheme": "Reasons for stocking specimens K(Tilapia) and L(Catfish) together in a pond:    Tilapia and catfish can co-exist successfully in ponds,  Tilapia and catfish have different feeding habits,  Tilapia is herbivorous while catfish is carnivorous,  Tilapia is a surface feeder while catfish is a bottom feeder,  Catfish checks/controls the population of tilapia which multiplies at a very fast rate and could overpopulate the pond,  Optimizing farmers' income/ harvest,  To ensure adequate utilization of the pond's space.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2020>4>b", "subject": "Agricultural Science Practical", "year": "2020", "type": "Practical", "sub_label": "b", "group": "", "topic": "ANIMAL PRODUCTION : AQUACULTURE", "question": "List four fishing gears used for harvesting specimens K and L in a pond", "images": [], "marking_scheme": "Fishing gears used for harvesting specimens K (Tilapia) and L (Catfish) in a pond:    Hook and line,  Fish trap  Fishing gourd  Use of nets e.g seine net, drag net, scoop net, cast net,  fishing spear/harpoons  basket", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2020>4>c", "subject": "Agricultural Science Practical", "year": "2020", "type": "Practical", "sub_label": "c", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "Name four products that could be made from specimen M(MILK)", "images": [], "marking_scheme": "Products that could be made from specimen M (milk):    Cheese,  Yoghurt,  Skimmed milk/ condensed/ can milk,  Casein,  Butter scotch,  Butter,  Ice cream,  Whey,  Milk Candy.", "marks": "1", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2020>4>d", "subject": "Agricultural Science Practical", "year": "2020", "type": "Practical", "sub_label": "d", "group": "", "topic": "ANIMAL PRODUCTION : AQUACULTURE", "question": "State four reasons for adding specimen N (LIME)  to the pond in which specimens K and L are stocked.", "images": [], "marking_scheme": "Reasons for adding specimen N (Lime) to the pond in which specimens K(Tilapia) and L(Catfish) are stocked:    Reduces pond acidity,  Reduces pond turbidity,  Makes fertilizers to be effective,  Supplies calcium for fish bone development,  Destroys leeches on tilapia and catfish skin,  To seal pores and prevent water loss,  To increase the availability of nutrient such as phosphorus in ponds with acid soil,  It reduces free carbon dioxide in pond water,  To encourage the growth of planktons.", "marks": "1", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2025>1>a", "subject": "Agricultural Science Practical", "year": "2025", "type": "Practical", "sub_label": "a", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "Specimen Description  Specimen A: Ammonium sulphate (labelled)    Specimen B: Muriate of potash (labelled)    Specimen C: Cow dung    Specimen D: Compost (labelled)    Specimen E: Cutlass    Specimen F: Spade    Specimen G: Wheelbarrow    Specimen H: Yam beetle    Specimen I: Cowpea weevil    Specimen J: Centrosema pubescens    Specimen K: Spear grass    Specimen L: Gizzard (chicken)    Specimen M: Goat skin (fresh, with hairs intact)    Specimen N: Horn    State two conditions that could necessitate the use of specimen A by farmers", "images": [], "marking_scheme": "Low soil nitrogen levels  Soil pH adjustment", "marks": "2", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2025>1>b", "subject": "Agricultural Science Practical", "year": "2025", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE", "question": "Give four methods of applying specimens A and B to soils", "images": [], "marking_scheme": "-Broadcasting: Spreading fertilizers evenly over the field.  -Band placement: Placing fertilizers in bands near the seeds or plants.  -Foliar application: Spraying fertilizers directly on plant leaves.  -Fertigation: Applying fertilizers through irrigation systems.", "marks": "4", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2025>1>c", "subject": "Agricultural Science Practical", "year": "2025", "type": "Practical", "sub_label": "c", "group": "", "topic": "CROP PRODUCTION : CLASSIFICATION OF CROPS", "question": "Name four crops that could require the application of specimen B", "images": [], "marking_scheme": "-Potatoes  -Bananas  -Sugarcane  -Tomatoes", "marks": "4", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2025>1>d", "subject": "Agricultural Science Practical", "year": "2025", "type": "Practical", "sub_label": "d", "group": "", "topic": "ORGANIC MANURE AND FERTILIZER", "question": "Mention five advantages of adding specimen C to the soil", "images": [], "marking_scheme": "-Nutrient enrichment   -Improved soil structure  -Increased microbial activity  -Sustainable resource  -Reduced waste", "marks": "5", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2025>2>a", "subject": "Agricultural Science Practical", "year": "2025", "type": "Practical", "sub_label": "a", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "State three uses each of specimens E and F in agriculture", "images": [], "marking_scheme": "SPECIMEN E:  (i) Clearing bushes and shrubs  (ii) Harvesting crops like maize  (iii) Pruning branches of plants  (iv) Cutting wood for staking or fencing  (v) Weeding between crops  (vi) Digging shallow holes for planting    SPECIMEN F:  (i) Digging soil for planting  (ii) Turning and loosening the soil  (iii) Mixing soil with fertilizers or manure  (iv) Removing weeds  (v) Transplanting seedlings  (vi) Leveling and shaping seedbeds", "marks": "6", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2025>2>b", "subject": "Agricultural Science Practical", "year": "2025", "type": "Practical", "sub_label": "b", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "Draw specimen F and label its parts", "images": ["Agricultural Science Practical/imgs/2025/GE3KBT.jpg"], "marking_scheme": "", "marks": "4", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2025>2>c", "subject": "Agricultural Science Practical", "year": "2025", "type": "Practical", "sub_label": "c", "group": "", "topic": "AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS", "question": "Mention five ways of maintaining specimen G", "images": [], "marking_scheme": "(i) Clean regularly after each use  (ii) Lubricate the wheel regularly to reduce friction  (iii) Store in a dry, shaded place to prevent rust  (iv) Tighten all loose nuts and bolts  (v) Repaint rusting metal parts to prevent corrosion  (vi) Replace damaged or worn-out tyres  (vii) Avoid overloading to prevent frame damage  (viii) Inspect regularly and repair any damage promptly.", "marks": "5", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2025>3>a", "subject": "Agricultural Science Practical", "year": "2025", "type": "Practical", "sub_label": "a", "group": "", "topic": "CROP PROTECTION : PESTS OF CROPS", "question": "Using specimen H, complete the table below.  Type of mouthpartNature of damage to cropOne effect on cropOne control measure", "images": [], "marking_scheme": "Type of mouthpartNature of damage to cropOne effect on cropOne control measureBiting and chewingBore holes into yam tubersReduces market value/yieldUse of insecticides or pesticides", "marks": "4", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2025>3>b", "subject": "Agricultural Science Practical", "year": "2025", "type": "Practical", "sub_label": "b", "group": "", "topic": "CROP PROTECTION : WEEDS", "question": "State the method of dispersal of each of specimens J and K", "images": [], "marking_scheme": "J ( Centrosema pubescens ): Explosive mechanism (self-dispersal)  K ( Spear grass ): Wind dispersal", "marks": "2", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2025>3>c", "subject": "Agricultural Science Practical", "year": "2025", "type": "Practical", "sub_label": "c", "group": "", "topic": "CROP PRODUCTION : CLASSIFICATION OF CROPS", "question": "Give one reason each for the answers in 3(b)", "images": [], "marking_scheme": "J: The fruit bursts open when mature, scattering seeds.    K: The seeds are light and have hairy structures that allow them to be carried by wind.", "marks": "2", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2025>3>d", "subject": "Agricultural Science Practical", "year": "2025", "type": "Practical", "sub_label": "d", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "Mention three ways of controlling specimen J on the farm", "images": [], "marking_scheme": "(i) Regular weeding or slashing before seed formation  (ii) Use of selective herbicides  (iii) Crop rotation or planting cover crops that suppress its growth", "marks": "3", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2025>3>e", "subject": "Agricultural Science Practical", "year": "2025", "type": "Practical", "sub_label": "e", "group": "", "topic": "CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS", "question": "Give four reasons why specimen K is difficult to control on the farm", "images": [], "marking_scheme": "(i) It has an extensive underground rhizome system, which allows it to regrow even after cutting.  (ii) It reproduces both by seeds and vegetative parts, making it spread rapidly.  (iii) Its seeds are easily dispersed by wind, leading to quick colonization of nearby areas.  (iv) It is resistant to many common herbicides, making chemical control less effective.", "marks": "4", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2025>4>a>i", "subject": "Agricultural Science Practical", "year": "2025", "type": "Practical", "sub_label": "i", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "Give two functions of specimen L in chickens", "images": [], "marking_scheme": "-Digestion of food.  -Grinding of feed materials", "marks": "2", "difficulty": "1"}, {"id": "theory>Agricultural Science Practical>2025>4>a>ii", "subject": "Agricultural Science Practical", "year": "2025", "type": "Practical", "sub_label": "ii", "group": "", "topic": "ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT", "question": "State two features of specimen L which enable it to perform the functions given in 4ai", "images": [], "marking_scheme": "-Muscular walls for grinding.  -Presence of grit for breaking down food.", "marks": "2", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2025>4>b", "subject": "Agricultural Science Practical", "year": "2025", "type": "Practical", "sub_label": "b", "group": "", "topic": "ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS", "question": "Mention five ways in which specimen M is of economic importance to humans.", "images": [], "marking_scheme": "(i) Provides meat for food.  (ii) Supplies milk for consumption.  (iii) Produces wool or hair for textiles.  (iv) Used in agricultural labor.  (v) Source of manure for farming.", "marks": "5", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2025>4>c", "subject": "Agricultural Science Practical", "year": "2025", "type": "Practical", "sub_label": "c", "group": "", "topic": "PARASITES", "question": "Name three ectoparasites associated with specimen M", "images": [], "marking_scheme": "(i) Ticks.  (ii) Lice.  (iii) Mites.", "marks": "3", "difficulty": "2"}, {"id": "theory>Agricultural Science Practical>2025>4>d", "subject": "Agricultural Science Practical", "year": "2025", "type": "Practical", "sub_label": "d", "group": "", "topic": "PARASITES", "question": "Give three functions of specimen N to the farm animal that possesses it.", "images": [], "marking_scheme": "(i) Protection from predators.  (ii) Regulation of body temperature.  (iii) Aid in sensory perception", "marks": "3", "difficulty": "2"}];